(function() {
var dan_ch_1_Verses = [
  {num:1,words:[["O LE tausaga e tolu o le nofoaiga a Ioakima le tupu o Iuta na sau ai Nepukanesa le tupu o Papelonia i Ierusalema ma na vagaia.", "In the third year of the reign of Jehoiakim king of Judah came Nebuchadnezzar king of Babylon unto Jerusalem, and besieged it."]]},
  {num:2,words:[["Ona tuuina atu lea e le Alii i lana pule o Ioakima le tupu o Iuta,", "And the Lord gave Jehoiakim king of Judah into his hand,"], ["faatasi ma nisi ipu o le fale o le Atua,", "with part of the vessels of the house of God:"], ["na ia ave foi ia mea i le nuu o Senara i le fale o lona atua;", "which he carried into the land of Shinar to the house of his god;"], ["ua na ave foi ipu i le fale oloa o lona atua.", "and he brought the vessels into the treasure house of his god."]]},
  {num:3,words:[["Ona fai atu lea o le tupu ia Asepenasa,", "And the king spake unto Ashpenaz the master of his eunuchs,"], ["le alii e pule i ana eunuka,", "that he should bring certain of the children of Israel,"], ["na te au mai nisi o le fanauga a Isaraelu, o le fanau lava a le tupu,", "and of the king's seed,"], ["atoa foi ma nisi alii;", "and of the princes;"]]},
  {num:4,words:[["o tama e le ponā lava,", "Children in whom was no blemish,"], ["a ua aulelei,", "but well favoured,"], ["o e ua atamamai lava,", "and skilful in all wisdom,"], ["ma ua iloa mea uma,", "and cunning in knowledge,"], ["o e ua popoto lava,", "and understanding science,"], ["ma ua tatau ona latou tutū i le maota o le tupu,", "and such as had ability in them to stand in the king's palace,"], ["ia a'oa'oina foi i latou i tusi ma le gagana a Kaletaia.", "and whom they might teach the learning and the tongue of the Chaldeans."]]},
  {num:5,words:[["Ua poloai foi le tupu ia latou aai i lea aso ma lea aso i mea taumafa a le tupu,", "And the king appointed them a daily provision of the king's meat,"], ["atoa ma le uaina e inu ai o ia,", "and of the wine which he drank:"], ["ia tausia i latou i tausaga e tolu; a mavae ia,", "so nourishing them three years,"], ["ona latou tutū ai lea i luma o le tupu.", "that at the end thereof they might stand before the king."]]},
  {num:6,words:[["Sa ia i latou nisi o le fanauga a Iuta,", "Now among these were of the children of Judah,"], ["o Tanielu,", "Daniel,"], ["o Hanania,", "Hananiah,"], ["o Mesaelu,", "Mishael,"], ["atoa ma Asaria.", "and Azariah:"]]},
  {num:7,words:[["Ua faaigoa foi ia te i latou e le alii e pule i eunuka;", "Unto whom the prince of the eunuchs gave names: for he gave unto Daniel the name of Belteshazzar;"], ["ua na faaigoa ia Tanielu o Peletisara,", "and to Hananiah,"], ["a o Hanania o Sataraka lea,", "of Shadrach; and to Mishael,"], ["o Mesaelu foi o Mesako lea,", "of Meshach;"], ["o Asaria foi o Apeteniko lea.", "and to Azariah, of Abed-nego."]]},
  {num:8,words:[["A ua manatu Tanielu,", "But Daniel purposed in his heart that he would not defile himself with the portion of the king's meat,"], ["o le a le leaga o ia i mea taumafa a le tupu, po o le uaina e inu ai o ia;", "nor with the wine which he drank:"], ["ona aioi atu ai lea o ia i le alii e pule i eunuka ina ia le leaga ai o ia.", "therefore he requested of the prince of the eunuchs that he might not defile himself."]]},
  {num:9,words:[["Na faatupuina e le Atua le alofa mutimutivale o le alii e pule i eunuka ia Tanielu.", "Now God had brought Daniel into favour and tender love with the prince of the eunuchs."]]},
  {num:10,words:[["Ona faapea atu lea o le alii e pule i eunuka ia Tanielu, Ou te fefe a'u i lo'u alii le tupu,", "And the prince of the eunuchs said unto Daniel,"], ["na ia pule i a outou mea e 'ai,", "I fear my lord the king,"], ["ma a outou mea e inu;", "who hath appointed your meat and your drink:"], ["e iloa i se a e ia o outou mata ua fole, ua le pei o tama ua outou tupulaga? o le a alataia ai ona vaea o lo'u ulu e le tupu ona o outou.", "for why should he see your faces worse liking than the children which are of your sort? then shall ye make me endanger my head to the king."]]},
  {num:11,words:[["Ona faapea atu lea o Tanielu ia Melesara,", "Then said Daniel to Melzar,"], ["o le na tofia e le alii e pule i eunuka e pule ia Tanielu,", "whom the prince of the eunuchs had set over Daniel,"], ["ma Hanania,", "Hananiah,"], ["ma Mesaelu,", "Mishael,"], ["ma Asaria;", "and Azariah,"]]},
  {num:12,words:[["ia e tofotofo i au nei auauna i po e sefulu,", "Prove thy servants, I beseech thee,"], ["ia latou au mai ai ia te i matou ni fua o laau e aai ai,", "ten days;"], ["ma vai e inu ai.", "and let them give us pulse to eat, and water to drink."]]},
  {num:13,words:[["Ona e silasila lea i o matou mata,", "Then let our countenances be looked upon before thee,"], ["ma mata o tama o e aai i mea taumafa a le tupu,", "and the countenance of the children that eat of the portion of the king's meat: and as thou seest,"], ["ona e faia lea i au auauna e tusa ma lau silafaga.", "deal with thy servants."]]},
  {num:14,words:[["Ona usiusitai lea o ia ia te i latou i lena mea,", "So he consented to them in this matter,"], ["na ia tofotofo foi ia te i latou i po e sefulu.", "and proved them ten days."]]},
  {num:15,words:[["Ua mavae po e sefulu, ona iloa lea ua sili ona lalelei o latou mata mona tino lelei i tama uma e na aai i mea taumafa a le tupu.", "And at the end of ten days their countenances appeared fairer and fatter in flesh than all the children which did eat the portion of the king's meat."]]},
  {num:16,words:[["Ona aveeseina ai lea e Melesara a latou mea taumafa mai le tupu ,", "Thus Melzar took away the portion of their meat,"], ["atoa ma le uaina na fai a inu ai i latou,", "and the wine that they should drink;"], ["ua avatu fua o laau mā latou.", "and gave them pulse."]]},
  {num:17,words:[["A o ia tama e toafa ua foaiina e le Atua ia te i latou le faautauta ma le atamai i tusi uma lava,", "As for these four children,"], ["atoa ma le poto;", "God gave them knowledge and skill in all learning and wisdom:"], ["a o Tanielu ua poto ia i faaaliga uma lava ma miti.", "and Daniel had understanding in all visions and dreams."]]},
  {num:18,words:[["Ua mavae foi aso na fai atu ai le tupu e au mai ai i latou,", "Now at the end of the days that the king had said he should bring them in,"], ["ona au mai ai lea o i latou e le alii e pule i eunuka i luma o Nepukanesa.", "then the prince of the eunuchs brought them in before Nebuchadnezzar."]]},
  {num:19,words:[["Ona tautalatala ai lea o le tupu ma i latou;", "And the king communed with them;"], ["a ua le maua se tasi o i latou e tusa ma Tanielu,", "and among them all was found none like Daniel,"], ["ma Hanania,", "Hananiah,"], ["ma Mesaelu,", "Mishael,"], ["ma Asaria;", "and Azariah:"], ["ona latou tutū ai lea i luma o le tupu.", "therefore stood they before the king."]]},
  {num:20,words:[["O mea uma lava e oo ai le poto ma le faautauta na fesili atu ai le tupu ia te i latou,", "And in all matters of wisdom and understanding,"], ["ua iloa ai e ia ua sāutuasefulu ona sili o lo latou poto i taulāitu,", "that the king enquired of them,"], ["ma vaafaatau uma i lona malo uma lava.", "he found them ten times better than all the magicians and astrologers that were in all his realm."]]},
  {num:21,words:[["Sa i ai Tanielu ua oo i le tausaga muamua o Kuresa le tupu.", "And Daniel continued even unto the first year of king Cyrus."]]},
];
renderVerseSet(dan_ch_1_Verses, 'dan-ch1-verses');

var dan_ch_2_Verses = [
  {num:1,words:[["Ua lua tausaga o le nofoaiga a Nepukanesa,", "And in the second year of the reign of Nebuchadnezzar Nebuchadnezzar dreamed dreams,"], ["ona fai ai lea o miti a Nepukanesa, ua atuatuvale ai lona finagalo,", "wherewith his spirit was troubled,"], ["ua le iloa e ia sina moe.", "and his sleep brake from him."]]},
  {num:2,words:[["Ona fai atu lea o le tupu e aami i taulāitu,", "Then the king commanded to call the magicians,"], ["ma vaafaatau,", "and the astrologers,"], ["ma e fai togafiti faataulāitu, atoa ma le au Kaletaia,", "and the sorcerers,"], ["e faailoa mai i le tupu ana miti;", "and the Chaldeans,"], ["ona latou o mai ai lea ma tutū i luma o le tupu.", "for to shew the king his dreams. So they came and stood before the king."]]},
  {num:3,words:[["Ona fai atu lea o le tupu ia te i latou,", "And the king said unto them,"], ["Ua fai la'u miti,", "I have dreamed a dream,"], ["ua atuatuvale ai lo'u loto i le fia iloa le miti.", "and my spirit was troubled to know the dream."]]},
  {num:4,words:[["Ona faapea mai ai lea o le au Kaletaia i le tupu i le upu Arama,", "Then spake the Chaldeans to the king in Syriack,"], ["Le tupu e,", "O king,"], ["ia soifua oe e faavavau. Ia e fetalaia mai le faalepo i au auauna,", "live for ever: tell thy servants the dream,"], ["ona matou faaali atu ai lea o le uiga.", "and we will shew the interpretation."]]},
  {num:5,words:[["Ua tali atu le tupu,", "The king answered and said to the Chaldeans,"], ["ua faapea atu i le au Kaletaia,", "The thing is gone from me:"], ["Ua mavae atu ia te au le mea;", "if ye will not make known unto me the dream,"], ["afai tou te le faailoa mai ia te au le miti ma lona uiga,", "with the interpretation thereof,"], ["o le a vaevaeniniiina outou,", "ye shall be cut in pieces,"], ["e fai foi o outou fale ma faatăfuna.", "and your houses shall be made a dunghill."]]},
  {num:6,words:[["A e afai tou te faailoa mai le miti ma lona uiga,", "But if ye shew the dream,"], ["tou te maua mai ia te au o mea alofa,", "and the interpretation thereof,"], ["ma le taui, atoa ma le mamalu tele;", "ye shall receive of me gifts and rewards and great honour:"], ["o lenei,", "therefore shew me the dream,"], ["ia outou faailoa mai ia te au le miti ma lona uiga.", "and the interpretation thereof."]]},
  {num:7,words:[["Ua toe tali mai i latou,", "They answered again and said,"], ["ua faapea mai, Ina fetalai mai ia le tupu i ana auauna le faalepo,", "Let the king tell his servants the dream,"], ["ona matou faailoa atu ai lea o lona uiga.", "and we will shew the interpretation of it."]]},
  {num:8,words:[["Ua tali atu le tupu,", "The king answered and said,"], ["ua faapea atu, Ua ou iloa lava tou te faatuatuai,", "I know of certainty that ye would gain the time,"], ["auā ua outou iloa ua mavae atu ia te au le mea.", "because ye see the thing is gone from me."]]},
  {num:9,words:[["A e afai tou te le faailoa mai ia te au le miti,", "But if ye will not make known unto me the dream,"], ["e tasi lava le tulafono ia te outou;", "there is but one decree for you:"], ["auā ua outou saunia upu pepelo ma le faa'ole'ole e fai mai ia te au, seia faatuatuai;", "for ye have prepared lying and corrupt words to speak before me,"], ["o lenei,", "till the time be changed:"], ["ina outou ta'u mai ia ia te au le miti,", "therefore tell me the dream,"], ["ona ou iloa ai lea ua outou mafaia ona faailoa mai ia te au lona uiga.", "and I shall know that ye can shew me the interpretation thereof."]]},
  {num:10,words:[["Ona tali mai ai lea o le au Kaletaia i le tupu,", "The Chaldeans answered before the king,"], ["ua faapea mai,", "and said,"], ["E leai se tagata i le lalolagi na te mafaia ona faailoa mai le mea a le tupu;", "There is not a man upon the earth that can shew the king's matter:"], ["o le mea lea e leai ai se tupu,", "therefore there is no king,"], ["po o se alii,", "lord, nor ruler,"], ["po o se faipule ua ia fetalaia mai se mea faapena i se taulāitu,", "that asked such things at any magician,"], ["po o se vaafaatau,", "or astrologer,"], ["po o se Kaletaia.", "or Chaldean."]]},
  {num:11,words:[["O le mea foi ua fetalai mai ai le tupu,", "And it is a rare thing that the king requireth,"], ["e faigata;", "and there is none other that can shew it before the king,"], ["e leai lava se tasi na te mafaia ona faailoa atu i le tupu, na o atua lava,", "except the gods,"], ["latou te le mau faatasi ma tagata.", "whose dwelling is not with flesh."]]},
  {num:12,words:[["O le mea lava lea na ita ai, ma matuā lili ai le tupu,", "For this cause the king was angry and very furious,"], ["ua fai atu foi ia faaumatia le au popoto uma o i Papelonia.", "and commanded to destroy all the wise men of Babylon."]]},
  {num:13,words:[["Ona oo atu ai lea o le poloaiga ia fasiotia le au popoto;", "And the decree went forth that the wise men should be slain;"], ["ona latou saili ai lea ia Tanielu ma ana uo ia fasiotia.", "and they sought Daniel and his fellows to be slain."]]},
  {num:14,words:[["Ona tali atu lea o Tanielu ma le faautauta ma le poto ia Arioka le pule i le 'au e faafeao i le tupu,", "Then Daniel answered with counsel and wisdom to Arioch the captain of the king's guard,"], ["o le na alu atu e fasioti i le au popoto o i Papelonia;", "which was gone forth to slay the wise men of Babylon:"]]},
  {num:15,words:[["ua tautala atu ia, ua faapea atu ia Arioka,", "He answered and said to Arioch the king's captain,"], ["le ua i ai le pule mai le tupu, Pe se a le mea ua tele vave ai le poloaiga a le tupu? Ona faailoa lea o le mea e Arioka ia Tanielu.", "Why is the decree so hasty from the king? Then Arioch made the thing known to Daniel."]]},
  {num:16,words:[["Ona ulufale atu ai lea o Tanielu,", "Then Daniel went in,"], ["ma faatoga atu i le tupu, se'i faatuatuai,", "and desired of the king that he would give him time,"], ["ona faailoa ai lea o le uiga i le tupu.", "and that he would shew the king the interpretation."]]},
  {num:17,words:[["Ona alu atu ai lea o Tanielu i lona fale,", "Then Daniel went to his house,"], ["ma na faailoa atu le mea ia Hanania,", "and made the thing known to Hananiah,"], ["ma Mesaelu,", "Mishael,"], ["ma Asaria,", "and Azariah,"], ["o ana uo,", "his companions:"]]},
  {num:18,words:[["ina ia latou faatoga atu ia alofa mai le Atua o le lagi i lenei mea ua lilo,", "That they would desire mercies of the God of heaven concerning this secret;"], ["ia le faaumatia Tanielu ma ana uo faatasi ma le au popoto uma o i Papelonia.", "that Daniel and his fellows should not perish with the rest of the wise men of Babylon."]]},
  {num:19,words:[["Ona faaali mai ai lea i le faaaliga i le po ia Tanielu o le mea sa lilo; ona faamanū ai lea o Tanielu i le Atua o le lagi.", "Then was the secret revealed unto Daniel in a night vision. Then Daniel blessed the God of heaven."]]},
  {num:20,words:[["Ua fai atu Tanielu, ua faapea atu,", "Daniel answered and said,"], ["Ia viia le suafa o le Atua e faavavau,", "Blessed be the name of God for ever and ever:"], ["e faavavau lava; auā e ona le poto ma le mana.", "for wisdom and might are his:"]]},
  {num:21,words:[["O ia foi na te liua tausaga ma tau;", "And he changeth the times and the seasons:"], ["e aveeseina e ia o tupu,", "he removeth kings,"], ["e tofia foi e ia o tupu;", "and setteth up kings:"], ["e foaiina mai e ia le poto i e o popoto,", "he giveth wisdom unto the wise,"], ["ma le malamalama i e o iloa mafaufau.", "and knowledge to them that know understanding:"]]},
  {num:22,words:[["O ia na te faaalia mai mea loloto ma mea ua lilo;", "He revealeth the deep and secret things:"], ["ua na silafia le mea o loo o i le pouliuli,", "he knoweth what is in the darkness,"], ["o le malamalama foi la te mau faatasi ma ia.", "and the light dwelleth with him."]]},
  {num:23,words:[["Ou te faamanū ma vivii atu ia te oe,", "I thank thee,"], ["le Atua o o'u tamā,", "and praise thee,"], ["o le ua foaiina mai ia te au le poto ma le malosi;", "O thou God of my fathers, who hast given me wisdom and might,"], ["ua e faailoaina mai nei foi ia te au le mea sa matou aioi atu ai ia te oe;", "and hast made known unto me now what we desired of thee:"], ["auā ua e faailoa mai ia te i matou le mea a le tupu.", "for thou hast now made known unto us the king's matter."]]},
  {num:24,words:[["Ona ulufale atu ai lea o Tanielu ia Arioka,", "Therefore Daniel went in unto Arioch,"], ["le na tofia e le tupu e faaumatia le au popoto o i Papelonia;", "whom the king had ordained to destroy the wise men of Babylon:"], ["ua alu atu ia ma faapea atu ia te ia,", "he went and said thus unto him;"], ["Aua le faaumatia le au popoto o i Papelonia;", "Destroy not the wise men of Babylon:"], ["ta o ma oe i luma o le tupu,", "bring me in before the king,"], ["ona ou faailoa ai lea o le uiga i le tupu.", "and I will shew unto the king the interpretation."]]},
  {num:25,words:[["Ona faataalise lea ona ulu atu o Arioka ma Tanielu i luma o le tupu,", "Then Arioch brought in Daniel before the king in haste,"], ["ua na faapea atu ia te ia,", "and said thus unto him, I have found a man of the captives of Judah,"], ["Ua ou maua le tagata o le tafeaga o Iuta na te faailoa atu le uiga i le tupu.", "that will make known unto the king the interpretation."]]},
  {num:26,words:[["Ona fai mai lea o le tupu,", "The king answered and said to Daniel,"], ["ua faapea mai ia Tanielu o le ua igoa ia Peletisara,", "whose name was Belteshazzar,"], ["Ua e mafaia ea ona faailoa mai ia te au le miti na a'u iloa,", "Art thou able to make known unto me the dream which I have seen,"], ["atoa ma lona uiga?", "and the interpretation thereof?"]]},
  {num:27,words:[["Ua tali atu Tanielu i luma o le tupu,", "Daniel answered in the presence of the king,"], ["ua faapea atu,", "and said,"], ["E le mafai i e popoto,", "The secret which the king hath demanded cannot the wise men,"], ["ma vaafaatau,", "the astrologers,"], ["ma taulāitu,", "the magicians,"], ["ma e o popoto i fetu,", "the soothsayers,"], ["ona faaali atu i le tupu o le mea a le tupu ua lilo na ia fetalai atu ai.", "shew unto the king;"]]},
  {num:28,words:[["A o i ai le Atua i le lagi, o le na te faaalia mea ua lilo,", "But there is a God in heaven that revealeth secrets,"], ["ma faailoa mai ia Nepukanesa le tupu o mea e oo mai i aso amuli.", "and maketh known to the king Nebuchadnezzar what shall be in the latter days."], ["Sa faapea lau faalepo ma le mea na e silafia i lou tofaga.", "Thy dream, and the visions of thy head upon thy bed, are these;"]]},
  {num:29,words:[["O oe,", "As for thee, O king,"], ["le tupu e,", "thy thoughts came into thy mind upon thy bed,"], ["sa tutupu ou manatu i luga o lou tofaga i mea e oo mai i aso amuli. O le na te faaali mai mea ua lilo ua ia faailoa mai ia te oe o mea o le a oo mai.", "what should come to pass hereafter: and he that revealeth secrets maketh known to thee what shall come to pass."]]},
  {num:30,words:[["O a'u foi,", "But as for me,"], ["e lei faaalia mai ia te au lenei mea sa lilo ona o se poto ua ia te au e sili i tagata ola uma,", "this secret is not revealed to me for any wisdom that I have more than any living,"], ["na o lenei, ona ia faailoa i le tupu le uiga,", "but for their sakes that shall make known the interpretation to the king,"], ["ma ia e silafia manatunatu o lou finagalo.", "and that thou mightest know the thoughts of thy heart."]]},
  {num:31,words:[["O oe,", "Thou,"], ["le tupu e,", "O king,"], ["na e silafia,", "sawest,"], ["faauta foi o le tasi tupua tele;", "and behold a great image. This great image,"], ["o lenei tupua tele sa maeu lona matagofie,", "whose brightness was excellent,"], ["na tu i ou luma,", "stood before thee;"], ["sa matautia foi lona tino mai.", "and the form thereof was terrible."]]},
  {num:32,words:[["O le ulu o lenei tupua, o le auro lelei lea;", "This image's head was of fine gold,"], ["o lona fatafata ma ona lima,", "his breast and his arms of silver,"], ["o le ario ia; o lona manava ma ona ogavae o le 'apa memea ia.", "his belly and his thighs of brass,"]]},
  {num:33,words:[["O ona vae, e uamea ia,", "His legs of iron,"], ["o ona tapuvae o uamea isi mea, a o omea isi mea.", "his feet part of iron and part of clay."]]},
  {num:34,words:[["Na e silasila ua tofia le maa a e lei tofia i lima,", "Thou sawest till that a stone was cut out without hands,"], ["na lavea ai le tupua i ona tapuvae na fai i uamea ma omea,", "which smote the image upon his feet that were of iron and clay,"], ["ua nutililii ai ia mea.", "and brake them to pieces."]]},
  {num:35,words:[["Ona nutililii faatasiina ai lea o le uamea,", "Then was the iron,"], ["o le omea,", "the clay,"], ["o le 'apa memea,", "the brass,"], ["o le ario,", "the silver,"], ["atoa ma le auro,", "and the gold, broken to pieces together,"], ["ua pei o le aputi i le mea e soli ai saito,", "and became like the chaff of the summer threshingfloors;"], ["ua lelea i le matagi,", "and the wind carried them away,"], ["ua le maua lava se mea latou te i ai;", "that no place was found for them:"], ["a o le maa na lavea ai le tupua ua avea lea ma mauga tele,", "and the stone that smote the image became a great mountain,"], ["ua tumu ai le lalolagi uma.", "and filled the whole earth."]]},
  {num:36,words:[["O le faalepo lena,", "This is the dream;"], ["o le a matou ta'uina atu foi i le tupu lona uiga.", "and we will tell the interpretation thereof before the king."]]},
  {num:37,words:[["Le tupu e,", "Thou,"], ["o oe o le tupu o tupu;", "O king,"], ["auā ua foaiina mai ia te oe e le Atua o le lagi le malo,", "art a king of kings: for the God of heaven hath given thee a kingdom,"], ["ma le malosi,", "power,"], ["ma le mamalu,", "and strength,"], ["ma le viiga;", "and glory."]]},
  {num:38,words:[["ua na avatu foi ia te oe mea uma e mau ai tagata, ma manu o le vao,", "And wheresoever the children of men dwell,"], ["ma manu felelei,", "the beasts of the field and the fowls of the heaven hath he given into thine hand,"], ["ua tuuina atu ia mea uma i lau pule; o le ulu auro o oe lava lea.", "and hath made thee ruler over them all. Thou art this head of gold."]]},
  {num:39,words:[["A mavae atu oe, ona tu lea o le tasi malo,", "And after thee shall arise another kingdom inferior to thee,"], ["e le tusa ma oe; ma le tasi o lona tolu foi o malo,", "and another third kingdom of brass,"], ["o le 'apa memea lea, e pule foi lea i le lalolagi uma.", "which shall bear rule over all the earth."]]},
  {num:40,words:[["O lona fa foi o malo e malosi ia pei o le uamea;", "And the fourth kingdom shall be strong as iron:"], ["auā e nutililii ma tu'imomomo mea uma i le uamea,", "forasmuch as iron breaketh in pieces and subdueth all things: and as iron that breaketh all these,"], ["e pei o le uamea ona tu'imomomo o ia mea uma e faapea lea malo ona nutililii ma tu'imomomo.", "shall it break in pieces and bruise."]]},
  {num:41,words:[["E vaevaeina foi le malo,", "And whereas thou sawest the feet and toes,"], ["auā na e silafia tapuvae ma tamatamai vae o uamea isi mea,", "part of potters' clay,"], ["a o isi mea o omea a le fai ipu omea;", "and part of iron, the kingdom shall be divided;"], ["a e peitai e i ai lava ia te ia le malosi o le uamea,", "but there shall be in it of the strength of the iron,"], ["auā na e silafia le uamea ua filogia ma le omea a le fai ipu.", "forasmuch as thou sawest the iron mixed with miry clay."]]},
  {num:42,words:[["O tamatamai vae foi o uamea isi mea a o omea isi mea,", "And as the toes of the feet were part of iron,"], ["e faapea lava le malo,", "and part of clay, so the kingdom shall be partly strong,"], ["e malosi nisi mea a e vaivai nisi mea.", "and partly broken."]]},
  {num:43,words:[["Na e silafia le uamea ua fefiloi ma le omea a le fai ipu,", "And whereas thou sawest iron mixed with miry clay,"], ["e faapea foi ona filogia o i latou ma le fanau a tagata;", "they shall mingle themselves with the seed of men:"], ["a e latou te le pipii le tasi i le tasi,", "but they shall not cleave one to another,"], ["e pei ona le filogia o le uamea ma le omea.", "even as iron is not mixed with clay."]]},
  {num:44,words:[["O ona po o ia tupu e faatuina ai e le Atua o le lagi o le malo e le faaumatia e faavavau;", "And in the days of these kings shall the God of heaven set up a kingdom,"], ["o lea malo foi,", "which shall never be destroyed:"], ["e le tuuina atu ia i se tasi nuu,", "and the kingdom shall not be left to other people,"], ["na te tu'imomomoina ma faaumatia ia malo uma lava,", "but it shall break in pieces and consume all these kingdoms,"], ["a o ia e tumau lava e faavavau;", "and it shall stand for ever."]]},
  {num:45,words:[["e pei ona e silafia na tofia le maa i le mauga,", "Forasmuch as thou sawest that the stone was cut out of the mountain without hands,"], ["a e lei tofia i lima,", "and that it brake in pieces the iron,"], ["ma na tu'imomomoina le uamea,", "the brass,"], ["le 'apa memea,", "the clay,"], ["le omea,", "the silver,"], ["le ario,", "and the gold;"], ["atoa ma le auro. O mea ia ua faailoa mai ai e le Atua silisili i le tupu o mea e oo mai amuli;", "the great God hath made known to the king what shall come to pass hereafter:"], ["e moni lava le li'a,", "and the dream is certain,"], ["e faamaoni foi lona uiga.", "and the interpretation thereof sure."]]},
  {num:46,words:[["Ona faapaū fao ai lea o Nepukanesa le tupu,", "Then the king Nebuchadnezzar fell upon his face,"], ["ua ifo ia Tanielu,", "and worshipped Daniel,"], ["ua ia fai atu latou te avatu ia te ia se taulaga atoa ma mea manogi.", "and commanded that they should offer an oblation and sweet odours unto him."]]},
  {num:47,words:[["Ona fai atu lea o le tupu ia Tanielu,", "The king answered unto Daniel,"], ["ua faapea atu,", "and said,"], ["E moni,", "Of a truth it is,"], ["o lo outou Atua o le Atua o atua ia,", "that your God is a God of gods,"], ["ma le Alii o tupu,", "and a Lord of kings,"], ["o lē faaali foi i mea ua lilo,", "and a revealer of secrets,"], ["auā ua e mafaia ona faaali o lenei mea sa lilo.", "seeing thou couldest reveal this secret."]]},
  {num:48,words:[["Ona avatu ai lea e le tupu o le mamalu tele ia Tanielu,", "Then the king made Daniel a great man,"], ["ua na foai atu foi ia te ia mea alofa e tele ma le sili,", "and gave him many great gifts,"], ["na ia tofia foi o ia e pule i le itu malo uma o Papelonia,", "and made him ruler over the whole province of Babylon,"], ["ia sili foi o ia i e pule i le au popoto uma o Papelonia.", "and chief of the governors over all the wise men of Babylon."]]},
  {num:49,words:[["Ua faatoga atu Tanielu i le tupu,", "Then Daniel requested of the king,"], ["ona ia tofia lea o Sataraka,", "and he set Shadrach,"], ["o Mesako,", "Meshach,"], ["ma Apeteniko latou te pule i sauniga a le itu malo o Papelonia;", "and Abed-nego,"], ["a o Tanielu,", "over the affairs of the province of Babylon:"], ["sa nofo o ia i le faitotoa o le tupu.", "but Daniel sat in the gate of the king."]]},
];
renderVerseSet(dan_ch_2_Verses, 'dan-ch2-verses');

var dan_ch_3_Verses = [
  {num:1,words:[["Na faia e Nepukanesa le tupu o le tupua auro,", "Nebuchadnezzar the king made an image of gold,"], ["e onogafulu kupita o lona umi lea;", "whose height was threescore cubits,"], ["e ono kupita o lona lautele lea;", "and the breadth thereof six cubits: he set it up in the plain of Dura,"], ["na ia faatuina i le fanua laugatasi o Turu i le itu malo o Papelonia.", "in the province of Babylon."]]},
  {num:2,words:[["Ua tuu sāvali e Nepukanesa le tupu ia faapotopotoina alii sili,", "Then Nebuchadnezzar the king sent to gather together the princes,"], ["o faipule,", "the governors,"], ["o e pule i nuu,", "and the captains,"], ["o faamasino,", "the judges,"], ["o e tausi tupe,", "the treasurers,"], ["o e popoto i tulafono,", "the counsellors,"], ["o e faamatala tulafono,", "the sheriffs,"], ["atoa ma faipule uma o itu malo,", "and all the rulers of the provinces,"], ["ia o mai i le faasaina o le tupua na faatuina e Nepukanesa le tupu.", "to come to the dedication of the image which Nebuchadnezzar the king had set up."]]},
  {num:3,words:[["Ona potopoto mai ai lea o alii sili,", "Then the princes,"], ["o faipule o e pule i nuu,", "the governors,"], ["o faamasino,", "and captains,"], ["o e tausi tupe,", "the judges,"], ["o e popoto i tulafono,", "the treasurers, the counsellors,"], ["o e faamatala tulafono,", "the sheriffs,"], ["atoa ma faipule uma o itu malo,", "and all the rulers of the provinces,"], ["ua o mai i latou i le faasaina o le tupua na faatuina e le tupu o Nepukanesa;", "were gathered together unto the dedication of the image that Nebuchadnezzar the king had set up;"], ["ona latou tutū ai lea i luma o le tupua na faatuina e Nepukanesa.", "and they stood before the image that Nebuchadnezzar had set up."]]},
  {num:4,words:[["Ona alaga atu lea o lē tala'i ua leo tele,", "Then an herald cried aloud,"], ["O le upu ia te outou nuu e,", "To you it is commanded,"], ["ma atu nuu,", "O people, nations,"], ["ma gagana eseese.", "and languages,"]]},
  {num:5,words:[["Se itu aso tou te lagona ai le leo o le pu,", "That at what time ye hear the sound of the cornet,"], ["le faaili,", "flute,"], ["le kitara,", "harp,"], ["le sapeka,", "sackbut,"], ["le saniteri,", "psaltery,"], ["le sumefono,", "dulcimer,"], ["atoa ma laaupese uiga eseese uma,", "and all kinds of musick,"], ["tou te faapauu ai ma ifo i le tupua auro ua faatuina e le tupu o Nepukanesa.", "ye fall down and worship the golden image that Nebuchadnezzar the king hath set up:"]]},
  {num:6,words:[["Ai se tasi e le faapaū ma ifo e lafoina o ia i lea lava itu aso i totonu o le ogaumu e mu ai le afi.", "And whoso falleth not down and worshippeth shall the same hour be cast into the midst of a burning fiery furnace."]]},
  {num:7,words:[["O lenei foi,", "Therefore at that time,"], ["ua oo ina lagona e tagata uma le leo o le pu,", "when all the people heard the sound of the cornet,"], ["le faaili,", "flute,"], ["le kitara,", "harp,"], ["le sapeka,", "sackbut,"], ["le saniteri,", "psaltery,"], ["atoa ma laaupese uiga eseese uma,", "and all kinds of musick,"], ["ona faapauu ai lea o nuu uma,", "all the people,"], ["ma atu nuu,", "the nations,"], ["ma gagana eseese,", "and the languages,"], ["ua latou ifo i le tupua auro na faatuina e le tupu o Nepukanesa.", "fell down and worshipped the golden image that Nebuchadnezzar the king had set up."]]},
  {num:8,words:[["Ona o ane ai lea o tagata Kaletaia ua latou momoli i sa Iutā.", "Wherefore at that time certain Chaldeans came near, and accused the Jews."]]},
  {num:9,words:[["Ua latou tautala atu,", "They spake and said to the king Nebuchadnezzar,"], ["ua faapea atu i le tupu o Nepukanesa, Le tupu e,", "O king,"], ["ia soifua oe e faavavau.", "live for ever."]]},
  {num:10,words:[["Le tupu e,", "Thou,"], ["na faia e oe le tulafono i tagata uma ia faapauu ma ifo i le tupua auro pe a lagona le leo o le pu,", "O king, hast made a decree,"], ["le faaili,", "that every man that shall hear the sound of the cornet,"], ["le kitara,", "flute, harp,"], ["le sapeka,", "sackbut,"], ["le saniteri,", "psaltery,"], ["le sumefono,", "and dulcimer, and all kinds of musick,"], ["atoa ma laaupese uiga eseese uma lava.", "shall fall down and worship the golden image:"]]},
  {num:11,words:[["Ai se tasi ua le faapaū ma ifo,", "And whoso falleth not down and worshippeth,"], ["e lafoina o ia i totonu o le ogaumu o mu ai le afi.", "that he should be cast into the midst of a burning fiery furnace."]]},
  {num:12,words:[["O i ai tagata o sa Iutā,", "There are certain Jews whom thou hast set over the affairs of the province of Babylon,"], ["o e na tofia e oe e pule i sauniga o le itu malo o Papelonia,", "Shadrach,"], ["o Sataraka,", "Meshach,"], ["o Mesako,", "and Abed-nego;"], ["ma Apeteniko;", "these men,"], ["le tupu e,", "O king,"], ["ua le ava ia tagata ia te oe,", "have not regarded thee:"], ["latou te le auauna i ou atua,", "they serve not thy gods,"], ["ua le ifo foi i latou i le tupua auro ua e faatuina.", "nor worship the golden image which thou hast set up."]]},
  {num:13,words:[["Ona fai atu ai lea o Nepukanesa ma le lilivau ma le ita tele ia ta'ita'iina mai Sataraka,", "Then Nebuchadnezzar in his rage and fury commanded to bring Shadrach,"], ["ma Mesako,", "Meshach,"], ["ma Apeteniko. Ona latou ta'ita'iina ai lea o ia tagata i luma o le tupu.", "and Abed-nego. Then they brought these men before the king."]]},
  {num:14,words:[["Ua fai atu Nepukanesa,", "Nebuchadnezzar spake and said unto them,"], ["ua faapea atu ia te i latou,", "Is it true,"], ["Sataraka e,", "O Shadrach,"], ["Mesako e,", "Meshach,"], ["ma Apeteniko,", "and Abed-nego,"], ["pe se matuā manatu ea tou te le auauna i o'u atua,", "do not ye serve my gods,"], ["ma outou le ifo i le tupua auro na a'u faatuina?", "nor worship the golden image which I have set up?"]]},
  {num:15,words:[["O lenei,", "Now if ye be ready that at what time ye hear the sound of the cornet,"], ["afai ua saunia outou pe a outou lagona le leo o le pu,", "flute,"], ["le faaili,", "harp,"], ["le kitara,", "sackbut,"], ["le sapeka,", "psaltery,"], ["le saniteri,", "and dulcimer,"], ["le sumefono, atoa ma laaupese uiga eseese uma,", "and all kinds of musick,"], ["tou te faapauu ma ifo i le tupua ua a'u faia,", "ye fall down and worship the image which I have made;"], ["e lelei;", "well:"], ["a e afai tou te le ifo,", "but if ye worship not,"], ["e lafoina outou i lena lava itu aso i totonu o le ogaumu e mu ai le afi;", "ye shall be cast the same hour into the midst of a burning fiery furnace;"], ["o ai foi se Atua na te laveaiina outou ai la'u pule?", "and who is that God that shall deliver you out of my hands?"]]},
  {num:16,words:[["Ua tali mai Sataraka,", "Shadrach,"], ["Mesako,", "Meshach,"], ["ma Apeteniko,", "and Abed-nego,"], ["ua faapea mai i le tupu,", "answered and said to the king,"], ["Nepukanesa e,", "O Nebuchadnezzar,"], ["e le aoga ona matou tali atu ia te oe i lenei mea;", "we are not careful to answer thee in this matter."]]},
  {num:17,words:[["afai o lea,", "If it be so,"], ["ua mafai lo matou Atua,", "our God whom we serve is able to deliver us from the burning fiery furnace,"], ["matou te auauna i ai, ona laveai mai ia te i matou ai le ogaumu e mu ai le afi,", "and he will deliver us out of thine hand,"], ["na te laveaiina mai lava i matou ai lau pule le tupu.", "O king."]]},
  {num:18,words:[["A e peitai,", "But if not,"], ["a le o lea,", "be it known unto thee,"], ["ia e silafia e oe le tupu e, matou te le auauna i ou atua;", "O king,"], ["o le tupua auro foi ua e faatuina,", "that we will not serve thy gods,"], ["matou te le ifo i ai.", "nor worship the golden image which thou hast set up."]]},
  {num:19,words:[["Ona tumu ai lea o Nepukanesa i le ita tele,", "Then was Nebuchadnezzar full of fury,"], ["ua ese le tu o ona fofoga ia Sataraka, ma Mesako,", "and the form of his visage was changed against Shadrach,"], ["ma Apeteniko;", "Meshach,"], ["ua tautala atu ia,", "and Abed-nego:"], ["ua faapea atu, ia faaaasa le ogaumu,", "therefore he spake,"], ["ia faafitu ona sili i le ua masani ai ona tafuina.", "and commanded that they should heat the furnace one seven times more than it was wont to be heated."]]},
  {num:20,words:[["Ona fai atu ai lea o ia i tagata e sili ona totoa i ana 'au latou te fusifusi ia Sataraka,", "And he commanded the most mighty men that were in his army to bind Shadrach,"], ["ma Mesako,", "Meshach,"], ["ma Apeteniko,", "and Abed-nego,"], ["ia lafoina i le ogaumu e mu ai le afi.", "and to cast them into the burning fiery furnace."]]},
  {num:21,words:[["Ona fusifusia ai lea o ia tagata,", "Then these men were bound in their coats,"], ["atoa ma o latou ofuvae,", "their hosen,"], ["ma o latou ofu tino, ma o latou ofu talaloa,", "and their hats,"], ["atoa ma o latou ofu,", "and their other garments,"], ["ma ua lafoina i totonu i le ogaumu e mu ai le afi.", "and were cast into the midst of the burning fiery furnace."]]},
  {num:22,words:[["Ua tauanau le poloaiga a le tupu,", "Therefore because the king's commandment was urgent,"], ["ma le ogaumu ua aasa tele lava,", "and the furnace exceeding hot,"], ["o le mea lea na fano ai i le mumū o le afi o ia tagata e na avae ia Sataraka,", "the flame of the fire slew those men that took up Shadrach,"], ["ma Mesako,", "Meshach,"], ["ma Apeteniko.", "and Abed-nego."]]},
  {num:23,words:[["A o ia tagata e toatolu,", "And these three men,"], ["o Sataraka,", "Shadrach,"], ["o Mesako,", "Meshach,"], ["ma Apeteniko,", "and Abed-nego,"], ["ua pauu i latou o fusifusia i totonu o le ogaumu e mu ai le afi.", "fell down bound into the midst of the burning fiery furnace."]]},
  {num:24,words:[["Ona matuā ofo ai lea o Nepukanesa le tupu,", "Then Nebuchadnezzar the king was astonied,"], ["ua vave ona tulai,", "and rose up in haste,"], ["ua fai atu,", "and spake,"], ["ua faapea atu i ana tulafane, Pe na tatou le lafoina ea tagata e toatolu o fusifusia i totonu o le afi? Ua tali mai i latou,", "and said unto his counsellors,"], ["ua faapea mai i le tupu,", "Did not we cast three men bound into the midst of the fire? They answered and said unto the king,"], ["Le tupu e,", "True,"], ["sa faapea lava.", "O king."]]},
  {num:25,words:[["Ua tali atu o ia,", "He answered and said,"], ["ua faapea atu, Faauta,", "Lo,"], ["ua ou iloa tagata e toafa,", "I see four men loose,"], ["ua tatalaina,", "walking in the midst of the fire,"], ["ua feoai i totonu o le afi, ua le afaina lava i latou;", "and they have no hurt;"], ["ua tino mai lona toafa ua pei o se alo o le Atua.", "and the form of the fourth is like the Son of God."]]},
  {num:26,words:[["Ona faalatalata atu lea o Nepukanesa i le gutu o le ogaumu e mu ai le afi,", "Then Nebuchadnezzar came near to the mouth of the burning fiery furnace,"], ["ua fai atu ia,", "and spake,"], ["ua faapea atu,", "and said,"], ["Sataraka e,", "Shadrach,"], ["Mesako,", "Meshach,"], ["ma Apeteniko,", "and Abed-nego,"], ["o auauna a le Atua silisili,", "ye servants of the most high God,"], ["o mai ia,", "come forth,"], ["ina o mai.", "and come hither."], ["Ona o mai ai lea o Sataraka,", "Then Shadrach,"], ["Mesako,", "Meshach, and Abed-nego,"], ["ma Apeteniko mai totonu o le afi.", "came forth of the midst of the fire."]]},
  {num:27,words:[["Ona faapotopotoina ai lea o alii sili,", "And the princes,"], ["o faipule,", "governors,"], ["o e pule i nuu,", "and captains, and the king's counsellors,"], ["atoa ma tulafale a le tupu,", "being gathered together,"], ["ua latou matamata i ia tagata ua le mafaia i le afi ona muina o latou tino,", "saw these men,"], ["e leai foi so latou lauulu ua mu,", "upon whose bodies the fire had no power, nor was an hair of their head singed,"], ["e lei liua foi o latou ofuvae,", "neither were their coats changed,"], ["ua le namu afi lava i latou.", "nor the smell of fire had passed on them."]]},
  {num:28,words:[["Ua fai atu Nepukanesa,", "Then Nebuchadnezzar spake,"], ["ua faapea atu,", "and said,"], ["Ia faafetaia le Atua o Sataraka,", "Blessed be the God of Shadrach,"], ["Mesako,", "Meshach,"], ["ma Apeteniko,", "and Abed-nego, who hath sent his angel,"], ["o le na auina mai lana agelu,", "and delivered his servants that trusted in him,"], ["ua laveaiina ai ana auauna e na faatuatua ia te ia,", "and have changed the king's word,"], ["ua liliuina foi le upu a le tupu,", "and yielded their bodies,"], ["ma ua latou tuuina atu o latou tino ina ne'i latou auauna ma ifo i se tasi atua,", "that they might not serve nor worship any god,"], ["tau lava o lo latou lava Atua.", "except their own God."]]},
  {num:29,words:[["O le mea lea ou te pule ai,", "Therefore I make a decree,"], ["Ai se nuu,", "That every people,"], ["po o se atu nuu,", "nation,"], ["po o se gagana ese,", "and language,"], ["na te faia se upu vale i le Atua o Sataraka,", "which speak any thing amiss against the God of Shadrach,"], ["Mesako,", "Meshach,"], ["ma Apeteniko,", "and Abed-nego,"], ["e vaevaeniniiina i latou,", "shall be cut in pieces,"], ["e fai foi o latou fale ma faatăfuna;", "and their houses shall be made a dunghill:"], ["auā e leai se isi atua na te mafaia ona laveaiina faapena.", "because there is no other God that can deliver after this sort."]]},
  {num:30,words:[["Ona tomai lea o Sataraka,", "Then the king promoted Shadrach,"], ["Mesako,", "Meshach,"], ["ma Apeteniko i le itu malo o Papelonia,", "and Abed-nego,"], ["i le pule a le tupu.", "in the province of Babylon."]]},
];
renderVerseSet(dan_ch_3_Verses, 'dan-ch3-verses');

var dan_ch_4_Verses = [
  {num:1,words:[["O a'u o Nepukanesa le tupu,", "Nebuchadnezzar the king,"], ["o la'u upu lenei i nuu uma,", "unto all people,"], ["ma atu nuu,", "nations, and languages,"], ["ma gagana eseese o e nonofo i le lalolagi uma,", "that dwell in all the earth;"], ["ia tupu tele so outou manuia.", "Peace be multiplied unto you."]]},
  {num:2,words:[["Sa a'u manatu e tatau ona a'u faailoa atu faailoga ma vavega na faia ia te au e le Atua silisili ese.", "I thought it good to shew the signs and wonders that the high God hath wrought toward me."]]},
  {num:3,words:[["O ona faailoga ua matuā tetele, o ona vavega ua mamana lava ia;", "How great are his signs! and how mighty are his wonders! his kingdom is an everlasting kingdom,"], ["o lona malo o le malo e faavavau lea, o lana pule e āu tupulaga lea.", "and his dominion is from generation to generation."]]},
  {num:4,words:[["O a'u o Nepukanesa sa a'u filemu i lo'u fale,", "I Nebuchadnezzar was at rest in mine house,"], ["sa a'u manuia foi i lo'u maota.", "and flourishing in my palace:"]]},
  {num:5,words:[["Na fai la'u miti na ou fefe ai,", "I saw a dream which made me afraid,"], ["o o'u manatunatu foi i lo'u moega atoa ma mea na ou vaaia sa ou atuatuvale ai.", "and the thoughts upon my bed and the visions of my head troubled me."]]},
  {num:6,words:[["Ona a'u pule lea ia aumaia i o'u luma le au popoto uma o i Papelonia,", "Therefore made I a decree to bring in all the wise men of Babylon before me,"], ["ina ia latou faailoa mai ia te au le uiga o le miti.", "that they might make known unto me the interpretation of the dream."]]},
  {num:7,words:[["Ona o mai ai lea o taulāitu,", "Then came in the magicians,"], ["ma vaafaatau,", "the astrologers,"], ["ma le au Kaletaia,", "the Chaldeans,"], ["atoa ma e o popoto i fetu,", "and the soothsayers:"], ["ona a'u ta'uina atu lea o le miti ia te i latou,", "and I told the dream before them;"], ["a ua latou le faailoa mai ia te au lona uiga.", "but they did not make known unto me the interpretation thereof."]]},
  {num:8,words:[["Mulimuli ane,", "But at the last Daniel came in before me,"], ["ua sau i o'u luma Tanielu,", "whose name was Belteshazzar,"], ["o lona igoa o Peletisara, ua i ai le igoa o lo'u atua,", "according to the name of my god,"], ["o loo i ai foi le agaga o atua paia,", "and in whom is the spirit of the holy gods:"], ["ona a'u ta'uina atu lea ia te ia la'u miti,", "and before him I told the dream,"], ["ua faapea atu ,", "saying,"]]},
  {num:9,words:[["Peletisara e,", "O Belteshazzar,"], ["o le matai o taulāitu,", "master of the magicians,"], ["auā ua ou iloa o loo ia te oe le agaga o atua paia,", "because I know that the spirit of the holy gods is in thee,"], ["e leai se mea lilo e faigata ia te oe;", "and no secret troubleth thee,"], ["ia e ta'u mai ia te au o faaaliga na ou vaaia i la'u miti,", "tell me the visions of my dream that I have seen,"], ["atoa ma lona uiga.", "and the interpretation thereof."]]},
  {num:10,words:[["O faaaliga ia na a'u iloa i lo'u moega;", "Thus were the visions of mine head in my bed;"], ["faauta,", "I saw,"], ["na a'u iloa le laau i totonu o le lalolagi,", "and behold a tree in the midst of the earth,"], ["ua tele lava lona maualuga.", "and the height thereof was great."]]},
  {num:11,words:[["Ua tupu tele le laau,", "The tree grew,"], ["ma ua malosi,", "and was strong,"], ["o lona maualuga foi ua oo i le lagi,", "and the height thereof reached unto heaven,"], ["ua iloa mai o ia i le tuluiga o le lalolagi uma.", "and the sight thereof to the end of all the earth:"]]},
  {num:12,words:[["Ua matagofie ona lau,", "The leaves thereof were fair,"], ["ma lona fua ua tele,", "and the fruit thereof much,"], ["ua i ai foi mea e 'ai mā mea uma;", "and in it was meat for all:"], ["ua faapaoloina i ona lalo ifo o manu o le vao;", "the beasts of the field had shadow under it,"], ["o ona la ua toaga i ai manu felelei,", "and the fowls of the heaven dwelt in the boughs thereof,"], ["ua aai ai lava o mea ola uma.", "and all flesh was fed of it."]]},
  {num:13,words:[["Na ou vaaia i faaaliga i lo'u moega,", "I saw in the visions of my head upon my bed,"], ["faauta,", "and,"], ["o le leoleo, o le ua paia,", "behold,"], ["ua alu ifo ia mai le lagi.", "a watcher and an holy one came down from heaven;"]]},
  {num:14,words:[["Ua alaga tele o ia,", "He cried aloud,"], ["ua faapea atu,", "and said thus,"], ["Ina tuu ia i lalo le laau,", "Hew down the tree,"], ["ma vavae ese ona la;", "and cut off his branches,"], ["ina lulu ese ia ona lau,", "shake off his leaves,"], ["ma faataapeape ona fua;", "and scatter his fruit:"], ["ina ia sosola manu ai ona lalo ifo,", "let the beasts get away from under it,"], ["ma manu felelei ai ona la.", "and the fowls from his branches:"]]},
  {num:15,words:[["A o le tagutugutu o lona pogai,", "Nevertheless leave the stump of his roots in the earth,"], ["tuu ai pea ia i le eleele,", "even with a band of iron and brass,"], ["ia mau ai i le fusi uamea ma le 'apa memea i le mutia o le vao;", "in the tender grass of the field;"], ["ia faasūsūina i le sau mai le lagi,", "and let it be wet with the dew of heaven,"], ["ia fai foi lona tofi faatasi ma manu i le mutia o le laueleele;", "and let his portion be with the beasts in the grass of the earth:"]]},
  {num:16,words:[["ia liua lona loto tagata,", "Let his heart be changed from man's,"], ["ma ia tuuina atu ia te ia le loto o le manu,", "and let a beast's heart be given unto him;"], ["seia mavae atu ona tausaga e fitu.", "and let seven times pass over him."]]},
  {num:17,words:[["O le pule a le au leoleo lenei mea,", "This matter is by the decree of the watchers,"], ["o le upu a le au paia ua ala ai lenei mea,", "and the demand by the word of the holy ones:"], ["ina ia iloa e tagata ola ua pule lē Silisili ese i le malo o tagata,", "to the intent that the living may know that the most High ruleth in the kingdom of men,"], ["ua tuuina atu ai i le ua ia finagalo i ai,", "and giveth it to whomsoever he will,"], ["e tofia foi e ia e pule i ai tagata ua aupito faatauvaa.", "and setteth up over it the basest of men."]]},
  {num:18,words:[["O le miti lava lena na ou vaaia,", "This dream I king Nebuchadnezzar have seen. Now thou,"], ["o a'u o Nepukanesa le tupu;", "O Belteshazzar,"], ["o oe foi Peletisara e, ina e ta'u mai ia lona uiga,", "declare the interpretation thereof,"], ["auā e le mafaia e le au popoto uma i lo'u malo ona faailoa mai ia te au le uiga;", "forasmuch as all the wise men of my kingdom are not able to make known unto me the interpretation:"], ["a e mafai ia te oe;", "but thou art able;"], ["auā o loo ia te oe le agaga o atua paia.", "for the spirit of the holy gods is in thee."]]},
  {num:19,words:[["Ona fememeai ai lea o Tanielu,", "Then Daniel,"], ["ua igoa ia Peletisara,", "whose name was Belteshazzar,"], ["pe atoa le itu la e tasi,", "was astonied for one hour,"], ["ua atuatuvale foi i lona manatunatu.", "and his thoughts troubled him."], ["Ona fai atu lea o le tupu,", "The king spake, and said,"], ["ua faapea atu,", "Belteshazzar,"], ["Peletisara e,", "let not the dream,"], ["aua e te atuatuvale i le miti po o lona uiga.", "or the interpretation thereof, trouble thee."], ["Ua tali mai Peletisara,", "Belteshazzar answered and said,"], ["ua faapea mai,", "My lord,"], ["Lo'u alii e, ia i ai i e o ita atu ia te oe le faalepo;", "the dream be to them that hate thee,"], ["ia i ai i e o fai oe mo latou fili lona uiga.", "and the interpretation thereof to thine enemies."]]},
  {num:20,words:[["O le laau na e silafia,", "The tree that thou sawest,"], ["sa tupu tele ma le malosi,", "which grew,"], ["o lona maualuga ua oo i le lagi,", "and was strong, whose height reached unto the heaven,"], ["ua iloa mai i le lalolagi uma;", "and the sight thereof to all the earth;"]]},
  {num:21,words:[["o ona lau ua matagofie,", "Whose leaves were fair,"], ["ma ona fua ua tele,", "and the fruit thereof much,"], ["ua i ai foi mea e 'ai mā mea uma;", "and in it was meat for all;"], ["ua nonofo i ona lalo ifo manu o le vao,", "under which the beasts of the field dwelt,"], ["ua toaga foi i ona la o manu felelei,", "and upon whose branches the fowls of the heaven had their habitation:"]]},
  {num:22,words:[["le tupu e,", "It is thou,"], ["o oe lava lea;", "O king,"], ["ua tupu tele ma ua malosi,", "that art grown and become strong:"], ["auā o lou mamalu ua tele,", "for thy greatness is grown,"], ["ua oo i le lagi,", "and reacheth unto heaven,"], ["o lau pule foi ua oo i le tuluiga o le lalolagi.", "and thy dominion to the end of the earth."]]},
  {num:23,words:[["Na silafia e le tupu,", "And whereas the king saw a watcher and an holy one coming down from heaven,"], ["o le leoleo, o le ua paia,", "and saying,"], ["ua alu ifo ia mai le lagi,", "Hew the tree down,"], ["ua faapea atu,", "and destroy it;"], ["Ina tuu i lalo ia le laau,", "yet leave the stump of the roots thereof in the earth,"], ["ma faataumaoi i ai, a o le tagutugutu o lona pogai,", "even with a band of iron and brass,"], ["tuu ai pea ia i le eleele,", "in the tender grass of the field;"], ["ia mau ai i le fusi uamea ma le 'apa memea i le mutia o le vao;", "and let it be wet with the dew of heaven,"], ["ia faasūsūina ai foi i le sau mai le lagi, ia fai foi lona tofi faatasi ma manu o le vao,", "and let his portion be with the beasts of the field,"], ["seia mavae atu ona tausaga e fitu.", "till seven times pass over him;"]]},
  {num:24,words:[["Le tupu e,", "This is the interpretation,"], ["o lona uiga lenei,", "O king, and this is the decree of the most High,"], ["o le pule lava lenei a lē Silisili ese ua oo atu i lo'u alii le tupu;", "which is come upon my lord the king:"]]},
  {num:25,words:[["e tulia oe ia te'a ma tagata,", "That they shall drive thee from men,"], ["a e mau oe faatasi ma manu o le vao;", "and thy dwelling shall be with the beasts of the field,"], ["e te taumafa i le mutia e pei o povi,", "and they shall make thee to eat grass as oxen,"], ["e sūsū oe i le sau mai le lagi,", "and they shall wet thee with the dew of heaven,"], ["e mavae atu ai ou tausaga e fitu,", "and seven times shall pass over thee,"], ["seia e silafia ua pule lē Silisili ese i le malo o tagata,", "till thou know that the most High ruleth in the kingdom of men,"], ["na te tuuina atu ai foi i le ua ia finagalo i ai.", "and giveth it to whomsoever he will."]]},
  {num:26,words:[["Na fetalaia mai foi e tuu ai pea le tagutugutu o lona pogai;", "And whereas they commanded to leave the stump of the tree roots;"], ["e tumau pea lau nofoaiga,", "thy kingdom shall be sure unto thee,"], ["e fai mo oe pe a e silafia ua pule Le o i le lagi.", "after that thou shalt have known that the heavens do rule."]]},
  {num:27,words:[["O lenei,", "Wherefore,"], ["le tupu e, ia malie la'u upu ia te oe,", "O king,"], ["ia e lafoai au agasala,", "let my counsel be acceptable unto thee,"], ["a e fai le amiotonu,", "and break off thy sins by righteousness,"], ["ia e lafoai au amio faapiopio, a e alofa i e matitiva,", "and thine iniquities by shewing mercy to the poor;"], ["pe mafai ona faalevaleva ane ai lou filemu.", "if it may be a lengthening of thy tranquillity."]]},
  {num:28,words:[["Na oo ia mea uma ia Nepukanesa le tupu.", "All this came upon the king Nebuchadnezzar."]]},
  {num:29,words:[["Ua mavae masina e sefulu ma le lua ona fealuai ai lea o ia i luga o le maota o le malo i Papelonia.", "At the end of twelve months he walked in the palace of the kingdom of Babylon."]]},
  {num:30,words:[["Ua fai ane le tupu,", "The king spake,"], ["ua faapea ane,", "and said,"], ["E le o Papelonia tele ea lenei, na a'u faia i lo'u malosi tele lava,", "Is not this great Babylon,"], ["e fai ma fale o le malo,", "that I have built for the house of the kingdom by the might of my power,"], ["ia viia ai foi lo'u mamalu?", "and for the honour of my majesty?"]]},
  {num:31,words:[["A o tautala mai le tupu,", "While the word was in the king's mouth,"], ["ua tŭlei ifo le siufofoga mai le lagi,", "there fell a voice from heaven,"], ["ua faapea mai , Nepukanesa e,", "saying,"], ["le tupu,", "O king Nebuchadnezzar,"], ["o le fai atu nei ia te oe,", "to thee it is spoken;"], ["ua te'a ma oe le malo.", "The kingdom is departed from thee."]]},
  {num:32,words:[["E tulia oe ia te'a ma tagata,", "And they shall drive thee from men,"], ["e te mau faatasi ma manu o le vao,", "and thy dwelling shall be with the beasts of the field:"], ["e te 'ai i le mutia e pei o povi,", "they shall make thee to eat grass as oxen,"], ["e mavae atu ai ou tausaga e fitu,", "and seven times shall pass over thee,"], ["seia e iloa ua pule lē Silisili ese i le malo o tagata,", "until thou know that the most High ruleth in the kingdom of men,"], ["na te tuuina atu i ai foi i le ua ia finagalo i ai.", "and giveth it to whomsoever he will."]]},
  {num:33,words:[["O lea lava itu aso na taunuu ai le upu ia Nepukanesa;", "The same hour was the thing fulfilled upon Nebuchadnezzar:"], ["ona tulia lea o ia i tagata,", "and he was driven from men,"], ["ua 'ai foi o ia i mutia pei o povi,", "and did eat grass as oxen,"], ["ua sūsū lona tino i le sau mai le lagi,", "and his body was wet with the dew of heaven,"], ["ua oo ina tutupu o lona lauulu ua pei o fulufulu o aeto,", "till his hairs were grown like eagles' feathers,"], ["ma ona matiuu ua pei o atigivae o manu felelei.", "and his nails like birds' claws."]]},
  {num:34,words:[["Ua uma ia aso,", "And at the end of the days I Nebuchadnezzar lifted up mine eyes unto heaven,"], ["ona ou faasaga ae ai lea o'u mata i le lagi, o a'u o Nepukanesa,", "and mine understanding returned unto me,"], ["ona a'u toe atamai ai lea;", "and I blessed the most High,"], ["ona ou faafetai ai lea i lē Silisili ese,", "and I praised and honoured him that liveth for ever,"], ["ua ou faaneenee atu foi ma vivii atu ia te ia o lē soifua e faavavau, o lana pule o le pule e faavavau lea,", "whose dominion is an everlasting dominion,"], ["o lona malo foi e āu tupulaga lava lea.", "and his kingdom is from generation to generation:"]]},
  {num:35,words:[["O i latou uma o e nonofo i le lalolagi,", "And all the inhabitants of the earth are reputed as nothing:"], ["ua peiseai ua leai i latou;", "and he doeth according to his will in the army of heaven,"], ["ua ia faia foi e tusa ma lona finagalo i 'au o le lagi, atoa ma e o nonofo i le lalolagi;", "and among the inhabitants of the earth:"], ["e leai se tasi na te taofia lona aao,", "and none can stay his hand,"], ["pe fai atu ia te ia,", "or say unto him,"], ["O le a ea le mea e te fai na?", "What doest thou?"]]},
  {num:36,words:[["O ona po lava ia ua ou toe atamai ai;", "At the same time my reason returned unto me;"], ["ua toe foi mai ia te au lo'u mamalu ma lo'u matagofie,", "and for the glory of my kingdom,"], ["ina ia mamalu ai lo'u malo; o o'u tulafale foi ma alii sa ia te au,", "mine honour and brightness returned unto me;"], ["ua latou saili ia te au,", "and my counsellors and my lords sought unto me;"], ["ua faatumauina foi a'u i lo'u malo,", "and I was established in my kingdom,"], ["ma ua faaopoopoina mai ia te au le mamalu e tele.", "and excellent majesty was added unto me."]]},
  {num:37,words:[["O lenei, o a'u o Nepukanesa ou te faamanū atu,", "Now I Nebuchadnezzar praise and extol and honour the King of heaven,"], ["ma vivii atu, ma faaneenee atu i le Tupu o le lagi,", "all whose works are truth,"], ["e faamaoni ana galuega uma,", "and his ways judgment:"], ["ma ona ala ua tonu; na te mafaia foi ona faamaulaloina e o savavali ma le faamaualuga.", "and those that walk in pride he is able to abase."]]},
];
renderVerseSet(dan_ch_4_Verses, 'dan-ch4-verses');

var dan_ch_5_Verses = [
  {num:1,words:[["Na faia e Pelesara le tupu le faigā'ai tele ma alii e toaafe sa ia te ia,", "Belshazzar the king made a great feast to a thousand of his lords,"], ["ua na inu uaina foi i luma o le toaafe.", "and drank wine before the thousand."]]},
  {num:2,words:[["Ua fai ane Pelesara,", "Belshazzar,"], ["a o inu uaina,", "whiles he tasted the wine,"], ["ia aami i ipu auro ma ario na aumaia e Nepukanesa lona tamā nai le malumalu i Ierusalema,", "commanded to bring the golden and silver vessels which his father Nebuchadnezzar had taken out of the temple which was in Jerusalem;"], ["ina ia feinu ai le tupu,", "that the king, and his princes,"], ["ma alii sa ia te ia,", "his wives,"], ["ma ana avā,", "and his concubines,"], ["atoa ma ana palake.", "might drink therein."]]},
  {num:3,words:[["Ona latou au mai ai lea o ipu auro na aumaia nai le malumalu o le fale o le Atua i Ierusalema,", "Then they brought the golden vessels that were taken out of the temple of the house of God which was at Jerusalem;"], ["ona feinu ai lea o le tupu,", "and the king,"], ["ma alii sa ia te ia,", "and his princes, his wives,"], ["ma ana avā,", "and his concubines,"], ["atoa ma ana palake.", "drank in them."]]},
  {num:4,words:[["Sa latou feinu uaina,", "They drank wine,"], ["ma latou vivii atu i atua auro,", "and praised the gods of gold,"], ["ma ario,", "and of silver,"], ["o 'apa memea,", "of brass,"], ["o uamea,", "of iron,"], ["o laau,", "of wood,"], ["ma maa.", "and of stone."]]},
  {num:5,words:[["O lea lava itu po na oo mai ai tamatamai lima o le tagata,", "In the same hour came forth fingers of a man's hand,"], ["ma ua tusi i le panisina o le pa puipui ua feagai ma le tuugalamepa i le maota o le tupu;", "and wrote over against the candlestick upon the plaister of the wall of the king's palace:"], ["ua iloa foi e le tupu o le lima ua tusi.", "and the king saw the part of the hand that wrote."]]},
  {num:6,words:[["Ona liua lea o fofoga o le tupu,", "Then the king's countenance was changed,"], ["ua atuatuvale o ia i lona manatunatu,", "and his thoughts troubled him,"], ["ua tatalaina sootaga o lona papatua,", "so that the joints of his loins were loosed,"], ["o ona tulivae foi ua faafetoai le tasi i le tasi.", "and his knees smote one against another."]]},
  {num:7,words:[["Ua valaau atu le tupu ua leo tele,", "The king cried aloud to bring in the astrologers,"], ["ia o mai vaafaatau,", "the Chaldeans,"], ["ma le au Kaletaia, atoa ma e popoto i fetu;", "and the soothsayers. And the king spake,"], ["ua fai atu le tupu,", "and said to the wise men of Babylon,"], ["ua faapea atu i le au popoto o Papelonia,", "Whosoever shall read this writing,"], ["O le tagata na te faitaulia lena tusi,", "and shew me the interpretation thereof,"], ["ma faailoa mai ia te au lona uiga, e faaofuina o ia i le ofu pauli,", "shall be clothed with scarlet,"], ["e asoa o ia i le filifili auro,", "and have a chain of gold about his neck,"], ["e pule foi o ia i le malo na o le toalua e sili ia te ia.", "and shall be the third ruler in the kingdom."]]},
  {num:8,words:[["Ona o mai ai lea o le au popoto uma o le tupu,", "Then came in all the king's wise men:"], ["a ua le mafaia i latou ona faitau o le tusi,", "but they could not read the writing,"], ["ma faailoa i le tupu lona uiga.", "nor make known to the king the interpretation thereof."]]},
  {num:9,words:[["Ona atuatuvale tele ai lea o le tupu o Pelesara,", "Then was king Belshazzar greatly troubled,"], ["ua liua ona fofoga,", "and his countenance was changed in him,"], ["ua fememeai foi alii sa ia te ia.", "and his lords were astonied."]]},
  {num:10,words:[["Ua ulufale atu le sa'o tamaitai i le fale e fai ai taumafataga,", "Now the queen,"], ["ona o upu a le tupu ma alii sa ia te ia;", "by reason of the words of the king and his lords,"], ["ua fai atu le sa'o tamaitai,", "came into the banquet house:"], ["ua faapea atu,", "and the queen spake and said,"], ["Le tupu e,", "O king,"], ["ia soifua oe e faavavau;", "live for ever:"], ["aua ne'i atuatuvale i lou manatunatu,", "let not thy thoughts trouble thee,"], ["aua foi ne'i liua ou fofoga.", "nor let thy countenance be changed:"]]},
  {num:11,words:[["O loo i ai i lou malo le tasi tagata o i ai le agaga o atua paia,", "There is a man in thy kingdom,"], ["sa iloa foi ia te ia i ona po o lou tamā o le malamalama,", "in whom is the spirit of the holy gods; and in the days of thy father light and understanding and wisdom,"], ["ma le mafaufau,", "like the wisdom of the gods,"], ["ma le poto e tusa ma le poto o atua;", "was found in him; whom the king Nebuchadnezzar thy father,"], ["na tofia o ia e lou tamā le tupu o Nepukanesa,", "the king,"], ["o lou lava tamā le tupu e fai ma matai o taulāitu,", "I say, thy father,"], ["ma vaafaatau,", "made master of the magicians,"], ["ma le au Kaletaia,", "astrologers, Chaldeans,"], ["ma e popoto i fetu.", "and soothsayers;"]]},
  {num:12,words:[["Auā sa iloa i lena Tanielu,", "Forasmuch as an excellent spirit,"], ["o le na faaigoaina e le tupu,", "and knowledge,"], ["o Peletisara,", "and understanding,"], ["o le atamai tele,", "interpreting of dreams,"], ["ma le poto, ma le mafaufau,", "and shewing of hard sentences,"], ["e faamatalaina e ia o li'a,", "and dissolving of doubts,"], ["na te matea mai tupua,", "were found in the same Daniel,"], ["e talatalaina e ia mea faigata;", "whom the king named Belteshazzar:"], ["o lenei,", "now let Daniel be called,"], ["ia valaauina Tanielu na te faailoa mai le uiga.", "and he will shew the interpretation."]]},
  {num:13,words:[["Ona aumaia lea o Tanielu i luma o le tupu;", "Then was Daniel brought in before the king. And the king spake and said unto Daniel,"], ["ona fai atu lea o le tupu,", "Art thou that Daniel,"], ["ua faapea atu ia Tanielu,", "which art of the children of the captivity of Judah,"], ["O oe ea o Tanielu mai le tafeaga o sa Iutā na aumaia e lo'u tamā le tupu mai Iuta?", "whom the king my father brought out of Jewry?"]]},
  {num:14,words:[["Ua ou faalogo i le tala ia te oe, ua ia te oe le agaga o atua,", "I have even heard of thee,"], ["atoa ma le malamalama,", "that the spirit of the gods is in thee,"], ["ma le mafaufau, ma le poto ua sili ua ia te oe.", "and that light and understanding and excellent wisdom is found in thee."]]},
  {num:15,words:[["Ua uma ona aumaia i o'u luma le au popoto,", "And now the wise men,"], ["o vaafaatau,", "the astrologers,"], ["ina ia latou faitau ai lena tusi,", "have been brought in before me, that they should read this writing,"], ["ma faailoa mai ia te au lona uiga;", "and make known unto me the interpretation thereof:"], ["a ua le mafaia e i latou ona faailoa mai o le uiga o le upu.", "but they could not shew the interpretation of the thing:"]]},
  {num:16,words:[["A ua ou faalogo i le tala ia te oe,", "And I have heard of thee,"], ["ua e mafaia ona faamatala uiga,", "that thou canst make interpretations,"], ["ma talatalaina mea faigata;", "and dissolve doubts:"], ["o lenei,", "now if thou canst read the writing,"], ["afai ua e mafaia ona faitau mai o le tusi, ma faailoa mai ia te au lona uiga,", "and make known to me the interpretation thereof,"], ["e faaofuina oe i le ofu pāuli,", "thou shalt be clothed with scarlet,"], ["e asoa foi oe i le filifili auro,", "and have a chain of gold about thy neck,"], ["e pule foi oe i le malo na o le toalua e sili ia te oe.", "and shalt be the third ruler in the kingdom."]]},
  {num:17,words:[["Ona tali mai lea o Tanielu,", "Then Daniel answered and said before the king,"], ["ua faapea mai i luma o le tupu,", "Let thy gifts be to thyself,"], ["Tuu ai pea ia te oe au mea alofa, ia e avatu i se tasi au taui;", "and give thy rewards to another;"], ["a o le tusi ou te faitauina atu lava i le tupu,", "yet I will read the writing unto the king,"], ["ma faailoa ia te ia lona uiga.", "and make known to him the interpretation."]]},
  {num:18,words:[["O oe na le tupu e,", "O thou king,"], ["na foaiina e le Atua silisili ia Nepukanesa lou tamā o le malo,", "the most high God gave Nebuchadnezzar thy father a kingdom,"], ["ma le mamalu,", "and majesty,"], ["ma le viiga,", "and glory,"], ["ma le faaneeneega;", "and honour:"]]},
  {num:19,words:[["o le mamalu foi na ia foaiina atu ia teia,", "And for the majesty that he gave him,"], ["sa gatete ai ma matatau ai i ona luma o nuu,", "all people,"], ["ma atu nuu,", "nations,"], ["ma gagana eseese;", "and languages,"], ["na ia fasia le na ia finagalo i ai,", "trembled and feared before him: whom he would he slew;"], ["na ia faaola foi i le na ia finagalo i ai;", "and whom he would he kept alive;"], ["na ia faaeaina le na ia finagalo i ai,", "and whom he would he set up;"], ["na ia faamaulaloina foi le na ia finagalo i ai.", "and whom he would he put down."]]},
  {num:20,words:[["A ua oo ina faamaualugaina o lona loto,", "But when his heart was lifted up,"], ["ma ua maaa lona loto e faamaualuga ai,", "and his mind hardened in pride,"], ["ona tūleia lea o ia ai lona nofoālii,", "he was deposed from his kingly throne,"], ["na aveeseina foi ia te ia lona mamalu.", "and they took his glory from him:"]]},
  {num:21,words:[["Sa tulia foi o ia ua te'a ma tagata,", "And he was driven from the sons of men;"], ["o lona loto sa liua ua pei o le loto o le manu,", "and his heart was made like the beasts,"], ["sa mafuta faatasi o ia ma asini o le vao;", "and his dwelling was with the wild asses:"], ["sa taumafa o ia i le mutia pei o povi,", "they fed him with grass like oxen,"], ["sa sūsū foi lona tino i le sau mai le lagi,", "and his body was wet with the dew of heaven;"], ["ina seia silafia e ia ua pule le Atua silisili i le malo o tagata,", "till he knew that the most high God ruled in the kingdom of men,"], ["na te tofia i ai le ua ia finagalo i ai.", "and that he appointeth over it whomsoever he will."]]},
  {num:22,words:[["O oe foi lona alo,", "And thou his son,"], ["Pelesara e,", "O Belshazzar,"], ["e ui lava ina e silafia ia mea uma,", "hast not humbled thine heart,"], ["e te lei faamaulaloina lou finagalo,", "though thou knewest all this;"]]},
  {num:23,words:[["a ua e faamaualuga oe i le Alii o le lagi;", "But hast lifted up thyself against the Lord of heaven;"], ["ua aumaia foi i ou luma o ipu o lona malumalu,", "and they have brought the vessels of his house before thee,"], ["ua inu ai uaina e oe,", "and thou,"], ["ma alii ua ia te oe,", "and thy lords,"], ["o ou faletua,", "thy wives,"], ["ma au palake;", "and thy concubines,"], ["ua e vivii atu foi atua ario,", "have drunk wine in them;"], ["ma auro,", "and thou hast praised the gods of silver,"], ["ma 'apa memea,", "and gold, of brass,"], ["ma uamea,", "iron,"], ["ma laau,", "wood,"], ["ma maa,", "and stone,"], ["e le vaai i latou,", "which see not,"], ["e le lagona,", "nor hear,"], ["e le iloa ni mea;", "nor know:"], ["a o le Atua ua i lona aao lou mānava,", "and the God in whose hand thy breath is,"], ["ua ia te ia foi ou ala uma,", "and whose are all thy ways,"], ["e te lei vivii atu i ai.", "hast thou not glorified:"]]},
  {num:24,words:[["E i ai ona tuuina mai e ia o le lima;", "Then was the part of the hand sent from him;"], ["ona tusia ai lea o lenei tusi.", "and this writing was written."]]},
  {num:25,words:[["O lenei le tusi na tusia,", "And this is the writing that was written,"], ["Mene,", "MENE,"], ["Mene,", "MENE,"], ["Takele,", "TEKEL,"], ["Uperesa .", "UPHARSIN."]]},
  {num:26,words:[["O le uiga lenei o le upu,", "This is the interpretation of the thing:"], ["Mene ,", "MENE;"], ["Ua faitaulia e le Atua lou malo,", "God hath numbered thy kingdom,"], ["ua faaiuina.", "and finished it."]]},
  {num:27,words:[["Tekele ,", "TEKEL;"], ["Ua fuatia oe i le fuafaatautau,", "Thou art weighed in the balances,"], ["a ua iloa oe ua mamasagia.", "and art found wanting."]]},
  {num:28,words:[["Peresa ,", "PERES;"], ["Ua vaevaeina lou malo,", "Thy kingdom is divided,"], ["ua foaiina atu ia Metai ma Peresia.", "and given to the Medes and Persians."]]},
  {num:29,words:[["Ua fai atu Pelesara,", "Then commanded Belshazzar,"], ["ona latou faaofu ai lea ia Tanielu i le ofu pāuli,", "and they clothed Daniel with scarlet,"], ["ma le filifili auro e asoa ai,", "and put a chain of gold about his neck, and made a proclamation concerning him,"], ["ma ua latou tala'i atu ia pule o ia i le malo na o le toalua e sili ia te ia.", "that he should be the third ruler in the kingdom."]]},
  {num:30,words:[["O le po lava lea na fasiotia ai Pelesara le tupu o Kaletaia.", "In that night was Belshazzar the king of the Chaldeans slain."]]},
  {num:31,words:[["Na maua le malo o Tariu le Metai i le onogafulu ma le lua o ona tausaga.", "And Darius the Median took the kingdom, being about threescore and two years old."]]},
];
renderVerseSet(dan_ch_5_Verses, 'dan-ch5-verses');

var dan_ch_6_Verses = [
  {num:1,words:[["Ua finagalo Tariu ia tofia e pule i le malo o alii sili e tasi le selau ma le toaluafulu,", "It pleased Darius to set over the kingdom an hundred and twenty princes,"], ["latou te i ai i le malo uma lava.", "which should be over the whole kingdom;"]]},
  {num:2,words:[["Ua tofia foi alii silisili e toatolu,", "And over these three presidents;"], ["ua i ai Tanielu;", "of whom Daniel was first:"], ["latou te pule i ia alii sili, ina ia logologo mai ia alii sili ia te i latou,", "that the princes might give accounts unto them,"], ["ina ia le māumau mea a le tupu.", "and the king should have no damage."]]},
  {num:3,words:[["A ua sili lenei Tanielu i alii silisili ma alii sili,", "Then this Daniel was preferred above the presidents and princes,"], ["ina ua tele lona atamai,", "because an excellent spirit was in him;"], ["sa manatu foi le tupu ia tofia o ia e pule i le malo uma.", "and the king thought to set him over the whole realm."]]},
  {num:4,words:[["Ona tausaili lea e alii silisili ma alii sili ina ia maua se mea a le malo e faalani ai se sala ia Tanielu;", "Then the presidents and princes sought to find occasion against Daniel concerning the kingdom;"], ["a ua le maua e i latou se mea e faalani ai po o se mea leaga e tasi;", "but they could find none occasion nor fault;"], ["auā sa faamaoni o ia, ua le maua foi sona sese e tasi,", "forasmuch as he was faithful,"], ["po o se mea leaga.", "neither was there any error or fault found in him."]]},
  {num:5,words:[["Ona faapea atu ai lea o ia tagata,", "Then said these men,"], ["E le maua e i tatou se mea leaga i lenei Tanielu,", "We shall not find any occasion against this Daniel,"], ["pe afai tatou te le maua se mea ia te ia i le tulafono a lona Atua.", "except we find it against him concerning the law of his God."]]},
  {num:6,words:[["Ona lolofi atu ai lea o ia alii silisili ma alii sili i le tupu,", "Then these presidents and princes assembled together to the king,"], ["ua faapea atu ia te ia,", "and said thus unto him,"], ["Le tupu e, Tariu,", "King Darius,"], ["ia soifua oe e faavavau;", "live for ever."]]},
  {num:7,words:[["ua uma ona filifili o alii silisili uma o le malo,", "All the presidents of the kingdom,"], ["o faipule,", "the governors,"], ["ma alii sili uma, o tulafale,", "and the princes,"], ["atoa ma e pule i nuu,", "the counsellors,"], ["ia faatuina se tulafono a le tupu,", "and the captains,"], ["ma ia faamauina se vavao,", "have consulted together to establish a royal statute,"], ["ai se tasi na te faatoga atu se mea mai se tasi atua,", "and to make a firm decree,"], ["po o se tagata,", "that whosoever shall ask a petition of any God or man for thirty days,"], ["a e tau lava o oe e faatoga i ai , le tupu e,", "save of thee,"], ["i po e tolugafulu,", "O king,"], ["ia lafoina o ia i le lua o leona.", "he shall be cast into the den of lions."]]},
  {num:8,words:[["O lenei,", "Now,"], ["le tupu e,", "O king,"], ["ia e faamauina le vavao,", "establish the decree, and sign the writing,"], ["ma tusi le tusi,", "that it be not changed,"], ["ina ia le tālaina,", "according to the law of the Medes and Persians,"], ["faapei o tulafono a Metai ma Peresia ua le tālaina.", "which altereth not."]]},
  {num:9,words:[["O le mea lea na tusi ai e le tupu o Tariu le tusi ma le vavao.", "Wherefore king Darius signed the writing and the decree."]]},
  {num:10,words:[["Ua iloa e Tanielu ua tusia le tusi,", "Now when Daniel knew that the writing was signed,"], ["ona alu atu ai lea o ia i lona fale,", "he went into his house;"], ["ua avanoa faamalama o lona potu e faasaga i Ierusalema,", "and his windows being open in his chamber toward Jerusalem,"], ["ua ta'i foi faatolu i aso ona tootuli o ia i ona tulivae,", "he kneeled upon his knees three times a day,"], ["ma tatalo,", "and prayed,"], ["ma faafetai i luma o lona Atua,", "and gave thanks before his God,"], ["faapei ona masani ai o ia.", "as he did aforetime."]]},
  {num:11,words:[["Ona lolofi ane ai lea o ia tagata,", "Then these men assembled,"], ["ua maua Tanielu o loo o tatalo ma faatoga atu i luma o lona Atua.", "and found Daniel praying and making supplication before his God."]]},
  {num:12,words:[["Ona latou o atu ai lea,", "Then they came near,"], ["ua faapea atu i le tupu i a le vavao a le tupu,", "and spake before the king concerning the king's decree;"], ["E lei tusia ea o oe le vavao, ai se tasi tagata e faatoga atu i se tasi atua,", "Hast thou not signed a decree,"], ["po o se tasi tagata,", "that every man that shall ask a petition of any God or man within thirty days,"], ["a e tau lava o oe e faatoga i ai ,", "save of thee,"], ["le tupu e,", "O king,"], ["i po e tolugafulu,", "shall be cast into the den of lions? The king answered and said,"], ["e lafoina o ia i le lua o leona? Ua tali mai le tupu, ua faapea mai,", "The thing is true,"], ["E moni lava lea mea,", "according to the law of the Medes and Persians,"], ["faapei o tulafono a Metai ma Peresia e le tālaina.", "which altereth not."]]},
  {num:13,words:[["Ona latou tali atu lea,", "Then answered they and said before the king,"], ["ua faapea atu i le tupu,", "That Daniel,"], ["O lena Tanielu,", "which is of the children of the captivity of Judah,"], ["o le tagata o le tafeaga o Iuta, e le ava o ia ia te oe,", "regardeth not thee,"], ["le tupu e,", "O king,"], ["ma le vavao na e tusia,", "nor the decree that thou hast signed,"], ["a ua tatalo o ia ta'i foi faatolu i aso.", "but maketh his petition three times a day."]]},
  {num:14,words:[["Ua faalogo le tupu i na upu,", "Then the king,"], ["ona tiga tele ai lea o ia ia te ia lava,", "when he heard these words,"], ["ua naunau o ia ia laveaiina o Tanielu;", "was sore displeased with himself, and set his heart on Daniel to deliver him:"], ["ua oo ina goto le la o taumafai pea lava ia ina ia laveai ia te ia.", "and he laboured till the going down of the sun to deliver him."]]},
  {num:15,words:[["Ona lolofi ane ai lea o ia tagata i le tupu,", "Then these men assembled unto the king,"], ["ua faapea atu i le tupu,", "and said unto the king,"], ["Le tupu e,", "Know,"], ["ia e silafia le tulafono a Metai ma Peresia,", "O king,"], ["e le tālaina lava se vavao,", "that the law of the Medes and Persians is,"], ["po o se tulafono ua faamauina e le tupu.", "That no decree nor statute which the king establisheth may be changed."]]},
  {num:16,words:[["Ua fai atu le tupu,", "Then the king commanded,"], ["ona latou ta'ita'iina ane ai lea o Tanielu,", "and they brought Daniel,"], ["ua lafo ia te ia i le lua o leona.", "and cast him into the den of lions."], ["Ua fai atu le tupu, ua faapea atu ia Tanielu,", "Now the king spake and said unto Daniel,"], ["O lou Atua,", "Thy God whom thou servest continually,"], ["o le ua e auauna i ai e le aunoa, o ia na te laveaiina oe.", "he will deliver thee."]]},
  {num:17,words:[["Ua au mai foi le maa,", "And a stone was brought,"], ["ua tuu ai i le gutu o le lua,", "and laid upon the mouth of the den;"], ["ona faamaufaailogaina lea e le tupu i lana mama,", "and the king sealed it with his own signet,"], ["atoa ma le mama a alii sa ia te ia,", "and with the signet of his lords;"], ["ina ne'i liua le pule ia Tanielu.", "that the purpose might not be changed concerning Daniel."]]},
  {num:18,words:[["Ona alu atu lea o le tupu i lona maota ua le taumafa ia i lea po;", "Then the king went to his palace,"], ["e leai foi ni lauupese na avane i ona luma,", "and passed the night fasting: neither were instruments of musick brought before him:"], ["ma ua te'a ia te ia le moe.", "and his sleep went from him."]]},
  {num:19,words:[["Ua tulai le tupu i le vave ao,", "Then the king arose very early in the morning,"], ["ua faataalise atu i le lua o leona.", "and went in haste unto the den of lions."]]},
  {num:20,words:[["Ua oo ia i le lua,", "And when he came to the den,"], ["ona alaga atu lea o ia ma le leo faamamai ia Tanielu;", "he cried with a lamentable voice unto Daniel:"], ["ua fai atu le tupu,", "and the king spake and said to Daniel,"], ["ua faapea atu ia Tanielu,", "O Daniel,"], ["Tanielu e, le auauna a le Atua soifua,", "servant of the living God,"], ["ua mafai ea e lou Atua,", "is thy God,"], ["o le ua e auauna i ai e le aunoa,", "whom thou servest continually,"], ["ona laveai ia te oe ai leona?", "able to deliver thee from the lions?"]]},
  {num:21,words:[["Ona tali mai lea o Tanielu i le tupu,", "Then said Daniel unto the king,"], ["Le tupu e,", "O king,"], ["ia soifua oe e faavavau,", "live for ever."]]},
  {num:22,words:[["ua auina mai e lo'u Atua o lana agelu,", "My God hath sent his angel,"], ["ua punitia ai gutu o leona,", "and hath shut the lions' mouths,"], ["ua le afaina ai a'u;", "that they have not hurt me: forasmuch as before him innocency was found in me;"], ["auā ua silafia e ia ua leai sa'u amio i ona luma;", "and also before thee,"], ["e leai foi se mea leaga ua a'u faia i ou luma,", "O king,"], ["le tupu.", "have I done no hurt."]]},
  {num:23,words:[["Ona fiafia tele lea o le tupu ona o ia,", "Then was the king exceeding glad for him,"], ["ua ia fetalai atu ia aveina ae Tanielu ai le lua;", "and commanded that they should take Daniel up out of the den. So Daniel was taken up out of the den,"], ["ona aveina ae ai lea o Tanielu ai le lua, ua le afaina lava o ia,", "and no manner of hurt was found upon him,"], ["auā na ia faatuatua i lona Atua.", "because he believed in his God."]]},
  {num:24,words:[["Ua fai atu le tupu,", "And the king commanded,"], ["ona ta'ita'iina mai ai lea o ia tagata e na molia Tanielu,", "and they brought those men which had accused Daniel,"], ["ma ua lafo ia te i latou,", "and they cast them into the den of lions,"], ["atoa ma a latou fanau,", "them,"], ["ma a latou avā i le lua o leona;", "their children,"], ["ua manumalo leona ia te i latou,", "and their wives;"], ["ua lamupala o latou ivi uma,", "and the lions had the mastery of them,"], ["a o lei oo ifo i latou i le taele o le lua.", "and brake all their bones in pieces or ever they came at the bottom of the den."]]},
  {num:25,words:[["Ona tusi atu lea o le tupu o Tariu i nuu uma,", "Then king Darius wrote unto all people,"], ["ma atu nuu,", "nations,"], ["ma gagana eseese o e nonofo i le lalolagi uma,", "and languages,"], ["ua faapea atu ,", "that dwell in all the earth;"], ["Ia tupu tele so outou manuia.", "Peace be multiplied unto you."]]},
  {num:26,words:[["Ou te pule ina ia gatete ma matatau i luma o le Atua o Tanielu o tagata i itu malo uma i lo'u malo;", "I make a decree, That in every dominion of my kingdom men tremble and fear before the God of Daniel:"], ["auā o ia o le Atua e soifua,", "for he is the living God,"], ["e tumau o ia e faavavau,", "and stedfast for ever,"], ["e le faaumatia lona malo ma lana pule e oo i le gataaga.", "and his kingdom that which shall not be destroyed, and his dominion shall be even unto the end."]]},
  {num:27,words:[["E ana e faaola ma laveai,", "He delivereth and rescueth,"], ["ua faia foi e ia faailoga ma vavega i le lagi ma le lalolagi,", "and he worketh signs and wonders in heaven and in earth,"], ["o le na laveai ia Tanielu ai lima o leona.", "who hath delivered Daniel from the power of the lions."]]},
  {num:28,words:[["Sa manuia foi lenei Tanielu i le nofoaiga a Tariu,", "So this Daniel prospered in the reign of Darius,"], ["atoa ma le nofoaiga a Kuresa le Peresia.", "and in the reign of Cyrus the Persian."]]},
];
renderVerseSet(dan_ch_6_Verses, 'dan-ch6-verses');

var dan_ch_7_Verses = [
  {num:1,words:[["O le tausaga muamua o Pelesara le tupu o Papelonia na iloa e Tanielu le miti ma faaaliga i lona moega,", "In the first year of Belshazzar king of Babylon Daniel had a dream and visions of his head upon his bed:"], ["ona tusia lea e ia le miti,", "then he wrote the dream,"], ["ua na ta'u atu foi i mea uma.", "and told the sum of the matters."]]},
  {num:2,words:[["Ua fai atu Tanielu,", "Daniel spake and said,"], ["ua faapea atu,", "I saw in my vision by night,"], ["Na a'u iloa i mea na faaali mai i le po,", "and,"], ["faauta foi,", "behold,"], ["o matagi e fa o le lagi ua pesi tetele atu i le sami tele.", "the four winds of the heaven strove upon the great sea."]]},
  {num:3,words:[["Ona o ao ai lea mai le sami o manu feai tetele e fa,", "And four great beasts came up from the sea,"], ["ua eseese le tasi i le tasi.", "diverse one from another."]]},
  {num:4,words:[["O le muamua,", "The first was like a lion,"], ["ua pei se leona ia, ua fai foi apaau o le aeto;", "and had eagle's wings:"], ["na a'u vaavaai ina seia fufutiesea ona apaau,", "I beheld till the wings thereof were plucked,"], ["sa siitia foi ai le fogāeleele,", "and it was lifted up from the earth,"], ["sa faatuina lava i ona vae, pei se tagata,", "and made stand upon the feet as a man,"], ["ma ua foaiina atu i ai le loto o le tagata.", "and a man's heart was given to it."]]},
  {num:5,words:[["Faauta foi,", "And behold another beast,"], ["o le tasi manu feai, o lona lua lea,", "a second,"], ["ua pei o le urosa,", "like to a bear,"], ["ua tulai atu i le tasi itu; ua i lona gutu o ivi asoaso e tolu,", "and it raised up itself on one side,"], ["ua u ai i ona nifo,", "and it had three ribs in the mouth of it between the teeth of it:"], ["ua latou fai atu i ai,", "and they said thus unto it,"], ["ua faapea atu, Tulai ia,", "Arise,"], ["ina e 'ai tino e tele.", "devour much flesh."]]},
  {num:6,words:[["Mulimuli ane i lea mea na ou vaai atu,", "After this I beheld,"], ["faauta foi,", "and lo another,"], ["o le tasi pei o le nameri,", "like a leopard,"], ["ua i lona tua foi o apaau e fa o le manu lele;", "which had upon the back of it four wings of a fowl;"], ["ua i ai foi i le manu feai o ulu e fa;", "the beast had also four heads;"], ["sa tuuina atu foi i ai le pule.", "and dominion was given to it."]]},
  {num:7,words:[["Mulimuli ane i lea mea na ou iloa i faaaliga i le po,", "After this I saw in the night visions,"], ["faauta mai,", "and behold a fourth beast,"], ["o lona fa o manu feai,", "dreadful and terrible,"], ["ua matautia ma ua maaa,", "and strong exceedingly;"], ["ua matuā malosi lava; ua i ai foi nifo uamea tetele,", "and it had great iron teeth:"], ["ua ia 'aina ma lamupalaina,", "it devoured and brake in pieces,"], ["a o mea ua totoe,", "and stamped the residue with the feet of it:"], ["ua na soli i ona vae. E ese lava ia i manu feai uma na muamua ia te ia,", "and it was diverse from all the beasts that were before it;"], ["sa i ai foi nifo e sefulu i lona ulu .", "and it had ten horns."]]},
  {num:8,words:[["Na a'u manatunatu i nifo,", "I considered the horns,"], ["faauta foi,", "and, behold,"], ["o le tasi nifo itiiti ua tupu ae i le va o ia nifo ,", "there came up among them another little horn,"], ["ona fa'iesea lea i ona luma o nifo e tolu sa luai tutū;", "before whom there were three of the first horns plucked up by the roots:"], ["faauta foi,", "and,"], ["ua i lenei nifo o mata e pei o mata o le tagata,", "behold, in this horn were eyes like the eyes of man,"], ["atoa ma le gutu ua tautalatala i upu faasausili.", "and a mouth speaking great things."]]},
  {num:9,words:[["Na ou vaavaai ina seia tuu mai o nofoālii,", "I beheld till the thrones were cast down,"], ["ua tietie mai foi Lē ua mai anamuā ona aso,", "and the Ancient of days did sit,"], ["ua sinasina lona ofu e pei o le kiona,", "whose garment was white as snow,"], ["ma ona lauao e pei o le fulufulu mamoe e lelei;", "and the hair of his head like the pure wool:"], ["o lona nofoālii o le afi mumū ia,", "his throne was like the fiery flame,"], ["ua se afi ua mu ana mea e taavalevale a'i.", "and his wheels as burning fire."]]},
  {num:10,words:[["Ua tafe mai le afi ua alu atu nai ona luma,", "A fiery stream issued and came forth from before him:"], ["ua afe ni afe o e auauna ia te ia,", "thousand thousands ministered unto him,"], ["e mano ni mano o e laulaututū i ona luma;", "and ten thousand times ten thousand stood before him:"], ["ua nofoia le faamasinoga,", "the judgment was set,"], ["ma ua fofola tusi.", "and the books were opened."]]},
  {num:11,words:[["Ona ou vaavaai atu ai lea ona o upu faasausili na tautala mai e le nifo ua ou vaai atu ina seia fasimatea le manu feai,", "I beheld then because of the voice of the great words which the horn spake:"], ["ua faaumatia foi lona tino,", "I beheld even till the beast was slain, and his body destroyed,"], ["ma ua lafoina le afi mumū.", "and given to the burning flame."]]},
  {num:12,words:[["A o isi manu feai ua totoe,", "As concerning the rest of the beasts,"], ["ua aveeseina la latou pule; a ua faafualoaina lo latou ola,", "they had their dominion taken away:"], ["ua oo i le tausaga ma le tau.", "yet their lives were prolonged for a season and time."]]},
  {num:13,words:[["Na ou iloa i faaaliga i le po,", "I saw in the night visions,"], ["faauta foi,", "and,"], ["ua afio mai i ao o le lagi Lē e pei o le Atalii o le tagata,", "behold, one like the Son of man came with the clouds of heaven,"], ["ua oo foi ia i Lē ua mai anamua ona aso,", "and came to the Ancient of days,"], ["ua latou momoli ia te ia i ona luma.", "and they brought him near before him."]]},
  {num:14,words:[["Ua foaiina atu ia te ia le pule,", "And there was given him dominion,"], ["ma le viiga,", "and glory,"], ["ma le malo,", "and a kingdom,"], ["ina ia auauna ia te ia o nuu uma,", "that all people,"], ["ma atu nuu,", "nations, and languages,"], ["ma gagana eseese;", "should serve him:"], ["o lana pule o le pule e faavavau lea,", "his dominion is an everlasting dominion,"], ["e le mavae atu ia,", "which shall not pass away,"], ["o lona malo foi e le faaumatia.", "and his kingdom that which shall not be destroyed."]]},
  {num:15,words:[["O a'u o Tanielu sa tigaina lo'u loto i totonu ia te au,", "I Daniel was grieved in my spirit in the midst of my body,"], ["o faaaliga na ou iloa na ou atuatuvale ai.", "and the visions of my head troubled me."]]},
  {num:16,words:[["Ua ou soso atu i le tasi o e ua laulaututū,", "I came near unto one of them that stood by,"], ["ma fesili atu ia te ia i le uiga o ia mea uma. Ona ta'u mai ai lea o ia ia te au,", "and asked him the truth of all this. So he told me,"], ["ua faailoa mai foi ia te au le uiga o ia mea.", "and made me know the interpretation of the things."]]},
  {num:17,words:[["O ia manu tetele e fa i latou o tupu ia e toafa o le a tutū mai i le lalolagi.", "These great beasts, which are four, are four kings, which shall arise out of the earth."]]},
  {num:18,words:[["A e maua le malo e le au paia a lē Silisili ese,", "But the saints of the most High shall take the kingdom,"], ["e fai foi mo i latou le malo e faavavau,", "and possess the kingdom for ever,"], ["e faavavau lava.", "even for ever and ever."]]},
  {num:19,words:[["Ona a'u fia iloa lea o le uiga o lona fa o manu,", "Then I would know the truth of the fourth beast,"], ["o le ua uiga ese lava i nisi manu uma,", "which was diverse from all the others,"], ["ua matautia tele lava,", "exceeding dreadful,"], ["o ona nifo o uamea ia,", "whose teeth were of iron,"], ["o ona atigivae o 'apa memea ia;", "and his nails of brass;"], ["ua 'ai,", "which devoured,"], ["ua lamupala,", "brake in pieces,"], ["ua soli foi i ona vae mea na totoe.", "and stamped the residue with his feet;"]]},
  {num:20,words:[["Na a'u fia iloa foi le uiga o nifo e sefulu ua i lona ulu,", "And of the ten horns that were in his head,"], ["atoa ma le tasi ua tupu ae,", "and of the other which came up,"], ["ua pauu ai nifo e tolu i ona luma;", "and before whom three fell;"], ["o le nifo foi lea sa i ai mata,", "even of that horn that had eyes,"], ["ma le gutu o loo tautala a'i upu faasausili,", "and a mouth that spake very great things,"], ["o lona tino mai foi ua sili ona tele i nisi uma.", "whose look was more stout than his fellows."]]},
  {num:21,words:[["Na ou iloa atu ua fai taua foi lena nifo i le au paia,", "I beheld, and the same horn made war with the saints,"], ["ma ua manumalo ia te i latou;", "and prevailed against them;"]]},
  {num:22,words:[["ina seia afio mai Lē ua mai anamuā ona aso,", "Until the Ancient of days came,"], ["ma ua tuuina atu le faamasinoga i le au paia a lē Silisili ese;", "and judgment was given to the saints of the most High;"], ["ua oo mai foi ona po ua maua mai ai le malo e le au paia.", "and the time came that the saints possessed the kingdom."]]},
  {num:23,words:[["Ua fai mai o ia ua faapea mai,", "Thus he said,"], ["O lona fa o manu,", "The fourth beast shall be the fourth kingdom upon earth,"], ["o lona fa lea o malo i le lalolagi, e ese lea i malo uma,", "which shall be diverse from all kingdoms,"], ["na te 'aina foi le lalolagi uma,", "and shall devour the whole earth,"], ["ma soli i ai,", "and shall tread it down,"], ["ma olopalaina.", "and break it in pieces."]]},
  {num:24,words:[["O ona nifo foi e sefulu o lenei malo, o tupu e sefulu ia,", "And the ten horns out of this kingdom are ten kings that shall arise:"], ["o le a tutū mai;", "and another shall rise after them;"], ["e mulimuli ane foi ia te i latou ona tu mai o le tasi,", "and he shall be diverse from the first,"], ["e ese ia i e na muamua, e faatoilaloina e ia o tupu e toatolu.", "and he shall subdue three kings."]]},
  {num:25,words:[["Na te faia upu i lē Silisili ese, ma faaumatia le au paia a lē Silisili ese,", "And he shall speak great words against the most High,"], ["e manatu o ia e faaliliu i tausaga ma tulafono;", "and shall wear out the saints of the most High,"], ["e tuuina atu foi i latou i lana pule seia mavae le tausaga,", "and think to change times and laws:"], ["ma tausaga, ma le vaeluagalemu o le tausaga.", "and they shall be given into his hand until a time and times and the dividing of time."]]},
  {num:26,words:[["A e nofoia le faamasinoga,", "But the judgment shall sit,"], ["ona aveeseina ai lea e i latou o lana pule,", "and they shall take away his dominion,"], ["ia faaiuina ma faaumatia ia oo i le iuga.", "to consume and to destroy it unto the end."]]},
  {num:27,words:[["O le malo,", "And the kingdom and dominion,"], ["ma le pule, atoa ma le mamalu o le malo i lalo ifo o le lagi uma,", "and the greatness of the kingdom under the whole heaven,"], ["e tuuina atu ia i le nuu o le au paia a lē Silisili ese,", "shall be given to the people of the saints of the most High,"], ["o lona malo, o le malo e faavavau lea,", "whose kingdom is an everlasting kingdom,"], ["e auauna ma usiusitai ia te ia o pule uma lava.", "and all dominions shall serve and obey him."]]},
  {num:28,words:[["Ona gata lea o lea mea;", "Hitherto is the end of the matter. As for me Daniel,"], ["o a'u o Tanielu sa tele lo'u atuatuvale i o'u manatunatu,", "my cogitations much troubled me,"], ["sa liua foi o'u mata;", "and my countenance changed in me:"], ["a ua taofi lenei mea i lo'u loto.", "but I kept the matter in my heart."]]},
];
renderVerseSet(dan_ch_7_Verses, 'dan-ch7-verses');

var dan_ch_8_Verses = [
  {num:1,words:[["O le tolu o tausaga o le nofoaiga a le tupu o Pelesara,", "In the third year of the reign of king Belshazzar a vision appeared unto me,"], ["o a'u o Tanielu, na ou iloa le faaaliga,", "even unto me Daniel,"], ["e mulimuli ane i le na ou luai iloa.", "after that which appeared unto me at the first."]]},
  {num:2,words:[["Na ou iloa foi le faaaliga,", "And I saw in a vision; and it came to pass,"], ["na ou iloa ai a o i ai a'u i Susana i le maota,", "when I saw, that I was at Shushan in the palace,"], ["ua i ai i le itu malo o Elama;", "which is in the province of Elam;"], ["na ou iloa foi i le faaaliga sa a'u i ai e lata ane i le vaitafe o Ulai.", "and I saw in a vision, and I was by the river of Ulai."]]},
  {num:3,words:[["Na ou tepa ae,", "Then I lifted up mine eyes,"], ["ona ou iloa lea,", "and saw,"], ["faauta foi,", "and,"], ["ua tu i tafatafa o le vaitafe o le mamoe poa,", "behold,"], ["ua i ai nifo e lua,", "there stood before the river a ram which had two horns:"], ["o nifo foi ua uumi,", "and the two horns were high;"], ["a ua sili ona umi o le tasi i le tasi,", "but one was higher than the other,"], ["o le ua umi foi sa muliai tupu ia.", "and the higher came up last."]]},
  {num:4,words:[["Na ou iloa ua sua le mamoe poa i sisifo,", "I saw the ram pushing westward,"], ["ma le itu i matu,", "and northward,"], ["atoa ma le itu i toga;", "and southward;"], ["ua leai foi se manu e tasi ua mafai ona tu i ona luma,", "so that no beasts might stand before him,"], ["ua leai foi se na te laveai mai ai lona lima;", "neither was there any that could deliver out of his hand;"], ["a ua ia fai mea ua ia loto i ai,", "but he did according to his will,"], ["ma ua faasilisili lava ia.", "and became great."]]},
  {num:5,words:[["O a'u sa a'u manatunatu,", "And as I was considering,"], ["faauta foi,", "behold,"], ["o le 'oti poa ua sau mai sisifo i le fogāeleele uma,", "an he goat came from the west on the face of the whole earth,"], ["a ua le pai i le laueleele;", "and touched not the ground:"], ["ua i ai foi i le 'oti le nifo tele i le va o ona mata.", "and the goat had a notable horn between his eyes."]]},
  {num:6,words:[["Ua alu atu lava ia i le mamoe poa ua i ai nifo e lua,", "And he came to the ram that had two horns,"], ["o le na a'u iloa o tu i tafatafa o le vaitafe,", "which I had seen standing before the river,"], ["ua oso atu ia te ia ma lona malosi tele.", "and ran unto him in the fury of his power."]]},
  {num:7,words:[["Na ou iloa o ia,", "And I saw him come close unto the ram,"], ["ua ia faalatalata atu i le mamoe poa,", "and he was moved with choler against him,"], ["ua matuā lili ia te ia,", "and smote the ram,"], ["ma na tuīa le mamoe poa,", "and brake his two horns:"], ["ua gaugau ai ona nifo e lua; ua le lavā lava le mamoe poa ona tu i ona luma,", "and there was no power in the ram to stand before him,"], ["a ua na lafotuina ia i le eleele,", "but he cast him down to the ground,"], ["ma soli ia te ia;", "and stamped upon him:"], ["ua leai lava se na te laveaiina le mamoe poa ai lona lima.", "and there was none that could deliver the ram out of his hand."]]},
  {num:8,words:[["Ona faasilisili lava lea o le 'oti poa;", "Therefore the he goat waxed very great:"], ["ua oo ina malosi o ia,", "and when he was strong,"], ["ona gauiesea lea o le nifo tele; a ua tutupu ae ni nifo tetele e fa e sui a'i,", "the great horn was broken;"], ["ua faasaga foi i matagi e fa o le lagi.", "and for it came up four notable ones toward the four winds of heaven."]]},
  {num:9,words:[["Ua tupu ae foi ai totonu o le tasi o i latou o le tasi nifo itiiti,", "And out of one of them came forth a little horn,"], ["ua tupu tele lava ia i le itu i toga,", "which waxed exceeding great,"], ["ma sasae,", "toward the south, and toward the east,"], ["atoa ma le nuu matagofie.", "and toward the pleasant land."]]},
  {num:10,words:[["Ua tupu tele foi o ia,", "And it waxed great,"], ["ua oo i 'au e le lagi,", "even to the host of heaven;"], ["ma ua na lafotu ifo i le eleele nisi 'au atoa ma nisi fetu,", "and it cast down some of the host and of the stars to the ground,"], ["ma na soli i ai.", "and stamped upon them."]]},
  {num:11,words:[["Ua faasilisili o ia ua oo lava i le ave 'au,", "Yea,"], ["na ia aveesea le taulaga e fai i aso fai soo,", "he magnified himself even to the prince of the host, and by him the daily sacrifice was taken away,"], ["ua ia lafotuina foi lona malumalu paia.", "and the place of his sanctuary was cast down."]]},
  {num:12,words:[["Ona tuuina atu lea o 'au,", "And an host was given him against the daily sacrifice by reason of transgression,"], ["atoa ma le taulaga e fai i aso fai soo mo agasala,", "and it cast down the truth to the ground;"], ["ua ia lafotuina le upu moni i le eleele, ua ia fai foi lona loto ,", "and it practised,"], ["ma ua manuia.", "and prospered."]]},
  {num:13,words:[["Ona ou faalogo lea,", "Then I heard one saint speaking,"], ["ua tautala le tasi o le au paia,", "and another saint said unto that certain saint which spake,"], ["ua fai ane foi se tasi o le au paia ia te ia lava na tautala, Seia afea ea le faaaliga i la le taulaga e fai aso fai soo,", "How long shall be the vision concerning the daily sacrifice,"], ["ma le agasala e faatafuna ai,", "and the transgression of desolation,"], ["ona tuuina atu lea o le malumalu atoa ma 'au ia solia lava?", "to give both the sanctuary and the host to be trodden under foot?"]]},
  {num:14,words:[["Ona faapea mai lea o ia ia te au,", "And he said unto me,"], ["Seia atoa afiafi ma taeao e lua afe ma le tolu o selau,", "Unto two thousand and three hundred days;"], ["ona faapaiaina ai lea o le malumalu.", "then shall the sanctuary be cleansed."]]},
  {num:15,words:[["Na a'u iloa le faaaliga,", "And it came to pass, when I,"], ["o a'u lava o Tanielu,", "even I Daniel,"], ["ona a'u suesue ai lea o le uiga,", "had seen the vision, and sought for the meaning,"], ["faauta foi,", "then,"], ["ua tu mai i o'u luma se tasi ua tino mai pei se tagata.", "behold, there stood before me as the appearance of a man."]]},
  {num:16,words:[["Ona a'u lagona lea o le leo o le tagata i le va o auvai o Ulai,", "And I heard a man's voice between the banks of Ulai,"], ["ua valaau,", "which called,"], ["ua faapea ane,", "and said,"], ["Kaperielu e,", "Gabriel,"], ["ia e faamatalaina le faaaliga i lenei tagata .", "make this man to understand the vision."]]},
  {num:17,words:[["Ua ia sau e lata ane i le mea na a'u tu ai;", "So he came near where I stood:"], ["ua sau lava ia,", "and when he came,"], ["ona a'u fefe ai lea,", "I was afraid,"], ["ua ou faapaū fao;", "and fell upon my face:"], ["ona faapea mai lea o ia ia te au,", "but he said unto me,"], ["Ia e iloa,", "Understand,"], ["le atalii e o le tagata,", "O son of man:"], ["auā o ona po o le iuga e taunuu ai le faaaliga.", "for at the time of the end shall be the vision."]]},
  {num:18,words:[["O loo o tautala mai o ia ia te au,", "Now as he was speaking with me,"], ["ua ou moe gase faafaō lava i le eleele;", "I was in a deep sleep on my face toward the ground:"], ["a ua pai mai o ia ia te au,", "but he touched me,"], ["ma na faatuina a'u i luga.", "and set me upright."]]},
  {num:19,words:[["Ua ia faapea mai foi,", "And he said,"], ["Faauta mai,", "Behold,"], ["ou te faailoa ia te oe mea e tutupu i ona po e taufaaiu ai le toasa;", "I will make thee know what shall be in the last end of the indignation:"], ["auā o ona po ua tuupoina e oo ai le iuga.", "for at the time appointed the end shall be."]]},
  {num:20,words:[["O le mamoe poa na e iloa ua i ai nifo e lua, o tupu ia o Metai ma Peresia.", "The ram which thou sawest having two horns are the kings of Media and Persia."]]},
  {num:21,words:[["O le 'oti taufulufulu foi, o le tupu lea o Iavana;", "And the rough goat is the king of Grecia:"], ["a o le nifo tele o i le va o ona mata, o le tupu muamua lea.", "and the great horn that is between his eyes is the first king."]]},
  {num:22,words:[["Ua gau foi lena nifo ,", "Now that being broken,"], ["a ua tutū mai ai isi e fa e sui a'i,", "whereas four stood up for it,"], ["e tutū mai malo e fa mai le atu nuu,", "four kingdoms shall stand up out of the nation,"], ["a e le o i ai lona malosi.", "but not in his power."]]},
  {num:23,words:[["A oo i le gataaga o latou malo,", "And in the latter time of their kingdom,"], ["pe a faaatoatoaina agasala a e agasala,", "when the transgressors are come to the full,"], ["ona tu mai ai lea o le tupu mata saua,", "a king of fierce countenance, and understanding dark sentences,"], ["na te iloa foi upu e faigata.", "shall stand up."]]},
  {num:24,words:[["E tele lona malosi,", "And his power shall be mighty,"], ["a e le o lona lava malosi;", "but not by his own power:"], ["e faasilisili lava ia ona faaumatia, e manuia ia,", "and he shall destroy wonderfully,"], ["e fai foi lona loto ,", "and shall prosper,"], ["na te faaumatia i e malolosi,", "and practise,"], ["atoa ma le nuu paia.", "and shall destroy the mighty and the holy people."]]},
  {num:25,words:[["O lona faautauta foi na te faamanuia ai ana sauniga pepelo;", "And through his policy also he shall cause craft to prosper in his hand;"], ["e faasilisili o ia i lona loto, na te faaumatia foi tagata o toatele,", "and he shall magnify himself in his heart,"], ["a o maninoa;", "and by peace shall destroy many:"], ["e tulai atu foi o ia i le Alii o alii; e olopalaina,", "he shall also stand up against the Prince of princes;"], ["a e le se lima e olopalaina ai .", "but he shall be broken without hand."]]},
  {num:26,words:[["O le faaaliga o le afiafi ma le taeao sa ta'ua,", "And the vision of the evening and the morning which was told is true:"], ["ua faamaoni lea; ia e pupuni foi le faaaliga,", "wherefore shut thou up the vision;"], ["auā e tele ona aso.", "for it shall be for many days."]]},
  {num:27,words:[["O a'u o Tanielu,", "And I Daniel fainted,"], ["sa ou vaivai,", "and was sick certain days;"], ["na ou ma'i foi i isi aso; ona ou tulai lea,", "afterward I rose up,"], ["ma a'u faia le feau a le tupu;", "and did the king's business;"], ["na ou ofo tele i le faaaliga,", "and I was astonished at the vision,"], ["a ua le iloa e se tasi.", "but none understood it."]]},
];
renderVerseSet(dan_ch_8_Verses, 'dan-ch8-verses');

var dan_ch_9_Verses = [
  {num:1,words:[["O le tausaga muamua o Tariu le atalii o Asueru,", "In the first year of Darius the son of Ahasuerus,"], ["o le na tupu mai Metai,", "of the seed of the Medes,"], ["sa fai o ia ma tupu i le malo o Kaletaia,", "which was made king over the realm of the Chaldeans;"]]},
  {num:2,words:[["o le tausaga muamua o lana nofoaiga,", "In the first year of his reign I Daniel understood by books the number of the years,"], ["o a'u o Tanielu na a'u iloa ai i tusi le faitau o tausaga na fetalaia mai e Ieova ia Ieremia le perofeta, ia faaatoaina ai le faatafunaina o Ierusalema,", "whereof the word of the LORD came to Jeremiah the prophet,"], ["o tausaga e fitugafulu ia.", "that he would accomplish seventy years in the desolations of Jerusalem."]]},
  {num:3,words:[["Ona ou faasaga lea i le Alii le Atua e saili i le tatalo,", "And I set my face unto the Lord God,"], ["ma le faatoga,", "to seek by prayer and supplications,"], ["ma le anapogi,", "with fasting,"], ["ma le ie talatala,", "and sackcloth,"], ["ma le lefulefu.", "and ashes:"]]},
  {num:4,words:[["Na a'u tatalo ia Ieova lo'u Atua,", "And I prayed unto the LORD my God,"], ["ma ou faaali atu,", "and made my confession,"], ["ua ou faapea atu,", "and said,"], ["Le Alii e, o le Atua e sili ma le matautia,", "O Lord,"], ["o lē tausi i le feagaiga,", "the great and dreadful God,"], ["ma le alofa i e alofa atu ia te ia,", "keeping the covenant and mercy to them that love him,"], ["atoa ma e o tausiusi i ana poloaiga.", "and to them that keep his commandments;"]]},
  {num:5,words:[["Ua matou agasala,", "We have sinned,"], ["ma ua fai mea leaga,", "and have committed iniquity,"], ["ma ua matou agaleaga,", "and have done wickedly, and have rebelled,"], ["ua fouvale foi ina ua te'a ese ma au poloaiga ma au faamasinoga.", "even by departing from thy precepts and from thy judgments:"]]},
  {num:6,words:[["E lei faalogo i matou i au auauna le au perofeta,", "Neither have we hearkened unto thy servants the prophets,"], ["o e na tautala mai i lou suafa i o matou tupu,", "which spake in thy name to our kings,"], ["ma o matou alii,", "our princes,"], ["ma o matou tamā,", "and our fathers,"], ["atoa foi ma tagata uma o le nuu.", "and to all the people of the land."]]},
  {num:7,words:[["Le Alii e,", "O Lord,"], ["ua ia te oe le amiotonu,", "righteousness belongeth unto thee,"], ["a ua ia te i matou le masiasi,", "but unto us confusion of faces, as at this day;"], ["pei ona i ai i ona po nei,", "to the men of Judah,"], ["ua i tagata o Iuta,", "and to the inhabitants of Jerusalem,"], ["ma e sa nonofo i Ierusalema ma Isaraelu uma,", "and unto all Israel,"], ["o e ua latalata mai,", "that are near, and that are far off,"], ["atoa ma e ua mamao i nuu uma na e tulia ai i latou,", "through all the countries whither thou hast driven them,"], ["ona o a latou agasala na latou agasala ai ia te oe.", "because of their trespass that they have trespassed against thee."]]},
  {num:8,words:[["Le Alii e,", "O Lord,"], ["ua ia te i matou le masiasi,", "to us belongeth confusion of face,"], ["o matou tupu,", "to our kings,"], ["ma o matou alii,", "to our princes,"], ["atoa ma o matou tamā,", "and to our fathers,"], ["auā ua matou agasala ia te oe.", "because we have sinned against thee."]]},
  {num:9,words:[["O loo i le Alii, lo matou Atua,", "To the Lord our God belong mercies and forgivenesses,"], ["le alofa mutimutivale ma le faamagaloina o sala , auā ua matou fouvale ia te ia.", "though we have rebelled against him;"]]},
  {num:10,words:[["E lei faalogo foi i matou i le siufofoga o Ieova lo matou Atua,", "Neither have we obeyed the voice of the LORD our God,"], ["e savavali i ana tulafono,", "to walk in his laws,"], ["na ia tuuina mai ia i matou e ana auauna le au perofeta.", "which he set before us by his servants the prophets."]]},
  {num:11,words:[["O Isaraelu uma foi,", "Yea,"], ["ua latou solia au tulafono,", "all Israel have transgressed thy law,"], ["ma ua o ese,", "even by departing,"], ["ua le fia faalogo i lou siufofoga;", "that they might not obey thy voice;"], ["o lea ua faaooina mai ai ia te i matou le fetuu,", "therefore the curse is poured upon us,"], ["ma le malaia ua tusia i le tulafono a Mose le auauna a le Atua,", "and the oath that is written in the law of Moses the servant of God,"], ["auā ua matou agasala ia te ia.", "because we have sinned against him."]]},
  {num:12,words:[["Ua ia faataunuu ana afioga na ia fetalai mai ia te i matou,", "And he hath confirmed his words,"], ["atoa ma o matou faamasino o e na faamasino ia i matou,", "which he spake against us,"], ["ina ua ia faaoo mai ia i matou le malaia tele;", "and against our judges that judged us, by bringing upon us a great evil:"], ["auā e lei faia se mea i lalo o le lagi uma faapei ona faia i Ierusalema.", "for under the whole heaven hath not been done as hath been done upon Jerusalem."]]},
  {num:13,words:[["E pei ona tusia i le tulafono a Mose,", "As it is written in the law of Moses,"], ["ua faapea lava ona oo mai ia te i matou o nei mala uma;", "all this evil is come upon us:"], ["a ua matou le aioi atu i luma o Ieova lo matou Atua,", "yet made we not our prayer before the LORD our God,"], ["ina ia matou liliu ese i a matou agasala,", "that we might turn from our iniquities,"], ["ma mafaufau i lou faamaoni.", "and understand thy truth."]]},
  {num:14,words:[["Na silasila foi Ieova i le malaia,", "Therefore hath the LORD watched upon the evil,"], ["ma ua faaooina mai ai lava ia te i matou;", "and brought it upon us:"], ["auā ua amiotonu Ieova lo tatou Atua i ana galuega uma ua ia faia;", "for the LORD our God is righteous in all his works which he doeth:"], ["a ua matou le faalogo i lona siufofoga.", "for we obeyed not his voice."]]},
  {num:15,words:[["O lenei,", "And now,"], ["le Alii e,", "O Lord our God,"], ["lo matou Atua,", "that hast brought thy people forth out of the land of Egypt with a mighty hand,"], ["o le na aumaia lou nuu ma le aao malosi ai le nuu o Aikupito,", "and hast gotten thee renown,"], ["ua e maua foi viiga e pei ona fai i nei ona po;", "as at this day;"], ["ua matou agasala,", "we have sinned,"], ["ua matou amio leaga.", "we have done wickedly."]]},
  {num:16,words:[["Le Alii e,", "O Lord,"], ["ou te aioi atu ia te oe,", "according to all thy righteousness,"], ["ona o lau amiotonu uma,", "I beseech thee,"], ["ia e liliueseina lou toatamai ma lou toasa ai lau aai o Ierusalema,", "let thine anger and thy fury be turned away from thy city Jerusalem, thy holy mountain:"], ["o lou mauga paia;", "because for our sins,"], ["auā o a matou agasala,", "and for the iniquities of our fathers,"], ["ma amioletonu a o matou tamā ua avea ai Ierusalema atoa ma lou nuu ma luma e i latou uma o e vagavagai mai ia te i matou.", "Jerusalem and thy people are become a reproach to all that are about us."]]},
  {num:17,words:[["O lenei,", "Now therefore,"], ["lo matou Atua e,", "O our God,"], ["ia e faafofoga mai i le tatalo a lau auauna,", "hear the prayer of thy servant,"], ["atoa ma ana faatoga,", "and his supplications,"], ["ma ia malamalama atu ou fofoga i lou malumalu ua faatafunaina,", "and cause thy face to shine upon thy sanctuary that is desolate,"], ["ona o le Alii.", "for the Lord's sake."]]},
  {num:18,words:[["Lo'u Atua e,", "O my God,"], ["ia e liliu mai ou fofoga,", "incline thine ear,"], ["ma faafofoga mai;", "and hear;"], ["ia sisila mai ou fofoga,", "open thine eyes,"], ["ma e silasila mai i lo matou faatafunaina,", "and behold our desolations,"], ["atoa ma le aai ua faaigoa i lou suafa;", "and the city which is called by thy name:"], ["auā matou te le avatu lo matou aioi i ou luma ona o a matou amiotonu,", "for we do not present our supplications before thee for our righteousnesses,"], ["a o lou alofa tele.", "but for thy great mercies."]]},
  {num:19,words:[["Le Alii e,", "O Lord,"], ["ia e faafofoga mai. Le Alii e,", "hear;"], ["ia faamagalo mai. Le Alii e,", "O Lord,"], ["ia e faasagasaga mai,", "forgive;"], ["ma e faia lava;", "O Lord, hearken and do;"], ["aua le faatuatuai,", "defer not,"], ["ona o lau afio lava,", "for thine own sake,"], ["lo'u Atua e,", "O my God:"], ["auā ua igoa i lou suafa lau aai ma lou nuu.", "for thy city and thy people are called by thy name."]]},
  {num:20,words:[["O loo ou tautala atu ma tatalo,", "And whiles I was speaking,"], ["ma ta'uta'u atu a'u agasala,", "and praying,"], ["ma le agasala a lo'u nuu o Isaraelu,", "and confessing my sin and the sin of my people Israel,"], ["o loo fai foi lo'u aioi i luma o Ieova lo'u Atua mo le mauga paia o lo'u Atua;", "and presenting my supplication before the LORD my God for the holy mountain of my God;"]]},
  {num:21,words:[["o loo ou tautala lava i le tatalo,", "Yea, whiles I was speaking in prayer,"], ["ua pai mai ia te au le tagata o Kaperielu,", "even the man Gabriel,"], ["o le na a'u luai iloa i le faaaliga,", "whom I had seen in the vision at the beginning,"], ["o loo lele faataalise mai i le itu la o le taulaga afiafi.", "being caused to fly swiftly, touched me about the time of the evening oblation."]]},
  {num:22,words:[["Na ia a'oa'o mai,", "And he informed me,"], ["ma ua tautala mai ia te au,", "and talked with me,"], ["ua faapea mai,", "and said,"], ["Tanielu e,", "O Daniel,"], ["ua a'u sau nei e a'oa'o ia te oe e poto ai.", "I am now come forth to give thee skill and understanding."]]},
  {num:23,words:[["Na amataina au faatoga ona oo mai ai lea o le poloaiga;", "At the beginning of thy supplications the commandment came forth,"], ["i le ua ou sau ai e faailoa atu ia te oe ,", "and I am come to shew thee;"], ["auā ua alofateleina oe; o lenei,", "for thou art greatly beloved:"], ["ia e iloa le upu,", "therefore understand the matter,"], ["ma mafaufau i le faaaliga.", "and consider the vision."]]},
  {num:24,words:[["Ua atofaina vaiasosa e fitugafulu i lou nuu ma lau aai paia,", "Seventy weeks are determined upon thy people and upon thy holy city,"], ["e faauma ai le solitulafono,", "to finish the transgression,"], ["ma faaiu ai agasala;", "and to make an end of sins,"], ["e fai ai foi le togiola mo agasala,", "and to make reconciliation for iniquity,"], ["ma faaooina mai ai le amiotonu e faavavau,", "and to bring in everlasting righteousness,"], ["e faamaufaailogaina foi le faaaliga ma le valoaga,", "and to seal up the vision and prophecy,"], ["e faauuina ai foi le mea e silisili ona paia.", "and to anoint the most Holy."]]},
  {num:25,words:[["Ia e iloa foi ma manatunatu,", "Know therefore and understand,"], ["e afua mai i le oo atu o le poloaiga ia toe faia ma ia atiina ae Ierusalema,", "that from the going forth of the commandment to restore and to build Jerusalem unto the Messiah the Prince shall be seven weeks,"], ["e oo atu i le Mesia le Alii,", "and threescore and two weeks: the street shall be built again,"], ["e fitu vaiasosa ma vaiasosa e onogafulu ma le lua,", "and the wall,"], ["e toe faia le ala tele ma le pa i ona po lava o le puapuaga.", "even in troublous times."]]},
  {num:26,words:[["A mavae vaiasosa e onogafulu ma le lua,", "And after threescore and two weeks shall Messiah be cut off,"], ["ona fasiotia ai lea o le Mesia, a e leai se mea ia te ia;", "but not for himself:"], ["o le nuu o le alii o le a maliu mai,", "and the people of the prince that shall come shall destroy the city and the sanctuary;"], ["latou te faaumatia le aai ma le malumalu, o lona iuga foi ua se tafega lea;", "and the end thereof shall be with a flood,"], ["ua tuu le pule ia faatafunaina e oo i le iuga o le taua.", "and unto the end of the war desolations are determined."]]},
  {num:27,words:[["Na te faatumauina foi le feagaiga i tagata e toatele i le vaiasosa e tasi;", "And he shall confirm the covenant with many for one week:"], ["o le vaeluagalemu foi o le vaiasosa na te faagata ai le taulaga,", "and in the midst of the week he shall cause the sacrifice and the oblation to cease,"], ["atoa ma le mea foaifuaina, e i ai foi i le itu o le malumalu mea e inosia e faatafunaina a'i,", "and for the overspreading of abominations he shall make it desolate,"], ["seia oo i le iuga o le mea ua tuu pule i ai,", "even until the consummation,"], ["ma ua faaoo i le na te faatafunaina.", "and that determined shall be poured upon the desolate."]]},
];
renderVerseSet(dan_ch_9_Verses, 'dan-ch9-verses');

var dan_ch_10_Verses = [
  {num:1,words:[["O le tolu o tausaga o Kuresa le tupu o Peresia sa faaali mai ai le tasi mea ia Tanielu,", "In the third year of Cyrus king of Persia a thing was revealed unto Daniel,"], ["o le ua igoa ia Peletisara;", "whose name was called Belteshazzar;"], ["e moni le upu,", "and the thing was true,"], ["a e tele taua;", "but the time appointed was long:"], ["na ia iloa foi le mea,", "and he understood the thing,"], ["ma na iloa le faaaliga.", "and had understanding of the vision."]]},
  {num:2,words:[["O ona po ia, o a'u o Tanielu sa ou faanoanoa ai i vaiasosa atoatoa e tolu;", "In those days I Daniel was mourning three full weeks."]]},
  {num:3,words:[["e leai se mea lelei na a'u 'ai ai,", "I ate no pleasant bread,"], ["e leai foi se aano o manu,", "neither came flesh nor wine in my mouth,"], ["po o se uaina na oo i lo'u gutu, na ou le uu ai lava,", "neither did I anoint myself at all,"], ["ua oo ina mavae atu vaiasosa e tolu.", "till three whole weeks were fulfilled."]]},
  {num:4,words:[["O le aso e luafulu ma le fa o le masina muamua,", "And in the four and twentieth day of the first month,"], ["sa a'u i ai i le auvai o le vaitafe tele,", "as I was by the side of the great river,"], ["o Hitekelu lea.", "which is Hiddekel;"]]},
  {num:5,words:[["Ona a'u tepa ae lea ma ou vaai,", "Then I lifted up mine eyes,"], ["faauta foi,", "and looked,"], ["o le tasi tagata ua ofu i le ie lino,", "and behold a certain man clothed in linen,"], ["ma ua fusi lona sulugatiti i le auro lelei o Upasa.", "whose loins were girded with fine gold of Uphaz:"]]},
  {num:6,words:[["O lona tino foi ua pei o le tasesa lea,", "His body also was like the beryl,"], ["ma ona fofoga ua tino mai pei o le uila,", "and his face as the appearance of lightning,"], ["ma ona mata ua pei o lamepa mumū ia,", "and his eyes as lamps of fire,"], ["o ona lima foi ma ona vae ua pei o 'apa memea ua faapupulaina,", "and his arms and his feet like in colour to polished brass,"], ["o le siufofoga o lana fetalaiga ua pei o le taalili o le vao tagata e toatele.", "and the voice of his words like the voice of a multitude."]]},
  {num:7,words:[["A ua na o a'u lava o Tanielu na iloa le faaaliga;", "And I Daniel alone saw the vision:"], ["auā o tagata sa matou i ai na le iloa e i latou le faaaliga,", "for the men that were with me saw not the vision;"], ["a ua ootia i latou i le tetemu tele lava,", "but a great quaking fell upon them,"], ["na latou sosola foi ia lalafi ai i latou.", "so that they fled to hide themselves."]]},
  {num:8,words:[["Ua tuua toatasi lava na o a'u,", "Therefore I was left alone,"], ["ona a'u iloa lea o lena mea tele na faaalia mai,", "and saw this great vision,"], ["ona leai lea o se toe malosi ia te au; ua mavae lo'u matagofie,", "and there remained no strength in me:"], ["ua ou pulavale,", "for my comeliness was turned in me into corruption,"], ["ua leai lava se malosi ua toe ia te au.", "and I retained no strength."]]},
  {num:9,words:[["A ua ou lagona le siufofoga o lana afioga;", "Yet heard I the voice of his words:"], ["ua ou lagona le siufofoga o lana afioga,", "and when I heard the voice of his words,"], ["ona ou moegase ai lea o a'u ua faō,", "then was I in a deep sleep on my face,"], ["ua faō lava i le eleele.", "and my face toward the ground."]]},
  {num:10,words:[["Faauta foi,", "And,"], ["ua pai mai ia te au le lima,", "behold, an hand touched me,"], ["ma faatootuli ia te au i o'u tulivae ma o'u alofilima.", "which set me upon my knees and upon the palms of my hands."]]},
  {num:11,words:[["Ona ia faapea mai lea ia te au,", "And he said unto me,"], ["Tanielu e,", "O Daniel,"], ["o le tagata ua alofateleina,", "a man greatly beloved,"], ["ia e mafaufau i upu ou te fai atu ai ia te oe,", "understand the words that I speak unto thee,"], ["ma ia e tu i luga;", "and stand upright:"], ["auā ua auina mai nei a'u ia te oe.", "for unto thee am I now sent."], ["Ua uma ona fetalaia mai ia te au o nei upu, ona ou tu ai lea,", "And when he had spoken this word unto me,"], ["ua ou gatete.", "I stood trembling."]]},
  {num:12,words:[["Ona faapea mai ai lea o ia ia te au,", "Then said he unto me,"], ["Tanielu e,", "Fear not,"], ["aua le fefe;", "Daniel: for from the first day that thou didst set thine heart to understand,"], ["auā talu le luai aso na e sauni ai lou loto e mafaufau ma faatigaina oe e oe i luma o lou Atua,", "and to chasten thyself before thy God,"], ["sa faafofogaina au upu,", "thy words were heard,"], ["ua a'u sau foi ona o au upu.", "and I am come for thy words."]]},
  {num:13,words:[["A o le alii o le malo o Peresia na ia tetee ia te au i po e luafulu ma le tasi;", "But the prince of the kingdom of Persia withstood me one and twenty days:"], ["faauta foi,", "but, lo,"], ["o Mekaeli o so le au alii sili ia,", "Michael,"], ["na ia maliu mai e fesoasoani mai ia te au;", "one of the chief princes, came to help me;"], ["na tuua foi a'u i lea mea faatasi ma tupu o Peresia.", "and I remained there with the kings of Persia."]]},
  {num:14,words:[["O lenei, ua a'u sau e faailoa atu ia te oe mea e tutupu i lou nuu i ona po amuli;", "Now I am come to make thee understand what shall befall thy people in the latter days:"], ["auā e tuai ona po o le faaaliga.", "for yet the vision is for many days."]]},
  {num:15,words:[["Ua ia fetalai mai na upu ia te au,", "And when he had spoken such words unto me,"], ["ona ou faasaga lea o'u mata i le eleele,", "I set my face toward the ground,"], ["ua ou le magagana.", "and I became dumb."]]},
  {num:16,words:[["Faauta foi,", "And,"], ["o le tasi e pei se tagata ua pai mai i o'u laugutu;", "behold,"], ["ona ou tautala atu lea,", "one like the similitude of the sons of men touched my lips:"], ["ua faapea atu i le ua tu mai i o'u luma,", "then I opened my mouth,"], ["Le alii e,", "and spake, and said unto him that stood before me,"], ["ua a'u puapuagatia ona o le faaaliga,", "O my lord,"], ["ua leai,", "by the vision my sorrows are turned upon me,"], ["se malosi ua toe ia te au.", "and I have retained no strength."]]},
  {num:17,words:[["Ua mafai faapefea le auauna a lo'u nei alii ona tautala ma lo'u nei alii? auā o a'u ua leai lava so'u malosi,", "For how can the servant of this my lord talk with this my lord? for as for me, straightway there remained no strength in me,"], ["ua leai foi se mānava ua toe ia te au.", "neither is there breath left in me."]]},
  {num:18,words:[["Ona toe pai mai lea ia te au o le tasi ua tino mai pei se tagata,", "Then there came again and touched me one like the appearance of a man,"], ["ua ia faamalosi mai ia te au.", "and he strengthened me,"]]},
  {num:19,words:[["Ua faapea mai o ia,", "And said,"], ["O oe o le tagata ua alofateleina,", "O man greatly beloved,"], ["aua e te fefe,", "fear not: peace be unto thee,"], ["ia e manuia,", "be strong,"], ["ia e faamalosi,", "yea,"], ["ia e faamalosi lava.", "be strong."], ["Ua mavae mai lana fetalaiga ia te au,", "And when he had spoken unto me,"], ["ona ou malosi ai lea,", "I was strengthened,"], ["ma a'u faapea atu,", "and said,"], ["Ina fetalai mai ia lo'u alii;", "Let my lord speak;"], ["auā ua e faamalosi mai ia te au.", "for thou hast strengthened me."]]},
  {num:20,words:[["Ona faapea mai ai lea o ia,", "Then said he,"], ["Ua e iloa ea le mea ua a'u sau ai ia te oe? o lenei,", "Knowest thou wherefore I come unto thee? and now will I return to fight with the prince of Persia:"], ["o le a a'u toe foi e tau ma le alii o Peresia; faauta foi,", "and when I am gone forth,"], ["a a'u alu atu,", "lo,"], ["ona sau ai lea o le alii o Iavana.", "the prince of Grecia shall come."]]},
  {num:21,words:[["A e peitai ou te faaali atu ia te oe le mea ua tusia i le Tusi e faamaoni;", "But I will shew thee that which is noted in the scripture of truth:"], ["ua leai foi se tasi e fesoasoani mai ia te au i na mea,", "and there is none that holdeth with me in these things,"], ["ua na o Mekaeli lo outou alii.", "but Michael your prince."]]},
];
renderVerseSet(dan_ch_10_Verses, 'dan-ch10-verses');

var dan_ch_11_Verses = [
  {num:1,words:[["O a'u foi,", "Also I in the first year of Darius the Mede,"], ["na a'u tu atu i le tausaga muamua o Tariu le Metai,", "even I,"], ["e fesoasoani ma faamalosi ia te ia.", "stood to confirm and to strengthen him."]]},
  {num:2,words:[["O lenei foi, ou te faaali atu ia te oa le upu moni.", "And now will I shew thee the truth."], ["Faauta, e toe tutū mai tupu o Peresia e toatolu,", "Behold,"], ["a o lona toafa e sili lava ia ona mauoa ia te i latou uma;", "there shall stand up yet three kings in Persia;"], ["o lona malosi foi,", "and the fourth shall be far richer than they all:"], ["e maua i lona oloa, na te lagaina mai ai i latou uma e tau ma le malo o Iavana.", "and by his strength through his riches he shall stir up all against the realm of Grecia."]]},
  {num:3,words:[["E tulai foi le tupu lima malosi,", "And a mighty king shall stand up,"], ["e pule lava ia i malo e tele,", "that shall rule with great dominion,"], ["ma fai mea na te loto i ai.", "and do according to his will."]]},
  {num:4,words:[["A oo ina tulai o ia,", "And when he shall stand up,"], ["ona lepetia lea o lona malo,", "his kingdom shall be broken,"], ["ma vaevaeina i matagi e fa o le lagi,", "and shall be divided toward the four winds of heaven;"], ["a e le fai ma ana fanau,", "and not to his posterity,"], ["e le tusa foi ma lana pule e pule ai o ia;", "nor according to his dominion which he ruled:"], ["auā e liaiina lona malo,", "for his kingdom shall be plucked up,"], ["e fai foi mo nisi a e le o i latou.", "even for others beside those."]]},
  {num:5,words:[["E malosi foi le tupu o le itu i toga,", "And the king of the south shall be strong,"], ["ma le tasi alii e ia te ia;", "and one of his princes;"], ["e sili foi lona malosi i lona, e pule foi ia;", "and he shall be strong above him,"], ["o lana pule,", "and have dominion;"], ["o le pule tele lea.", "his dominion shall be a great dominion."]]},
  {num:6,words:[["A oo i le tuluiga o tausaga,", "And in the end of years they shall join themselves together;"], ["la te sosoo faatasi;", "for the king's daughter of the south shall come to the king of the north to make an agreement:"], ["auā o le afafine o le tupu o le itu i toga e sau o ia i le tupu o le itu i matu e fai ai se leleiga;", "but she shall not retain the power of the arm;"], ["a e le tumau ia te ia le lima malosi,", "neither shall he stand,"], ["e le tumau foi o ia, po o lona malosi;", "nor his arm:"], ["a e tuuina atu o ia,", "but she shall be given up,"], ["atoa ma i latou e molia o ia,", "and they that brought her,"], ["ma lē fanaua e ia,", "and he that begat her,"], ["atoa ma le na te faamalosia o ia i ia ona po.", "and he that strengthened her in these times."]]},
  {num:7,words:[["A o le tātupu o ona aa e tu mai ai se tasi i lana nofoaiga,", "But out of a branch of her roots shall one stand up in his estate,"], ["e sau foi o ia ma 'au,", "which shall come with an army,"], ["ma alu atu i le 'olo o le tupu o le itu i matu,", "and shall enter into the fortress of the king of the north, and shall deal against them,"], ["e fai lona loto ia te i latou ma manumalo ai.", "and shall prevail:"]]},
  {num:8,words:[["Na te avea foi faatagataotaua i Aikupito o latou atua,", "And shall also carry captives into Egypt their gods,"], ["ma o latou alii,", "with their princes,"], ["atoa ma o latou ipu manaomia o ario ma auro;", "and with their precious vessels of silver and of gold;"], ["e tumau foi o ia i tausaga e sili i tausaga o le tupu o le itu i matu.", "and he shall continue more years than the king of the north."]]},
  {num:9,words:[["E alu atu foi o ia i le malo o le tupu o le itu i toga,", "So the king of the south shall come into his kingdom,"], ["ma toe foi i lona lava nuu.", "and shall return into his own land."]]},
  {num:10,words:[["A o ona atalii la te laga mai,", "But his sons shall be stirred up, and shall assemble a multitude of great forces:"], ["ma la faapotopoto le vao 'au e tele;", "and one shall certainly come,"], ["ona matuā sau ai lea o le tasi ,", "and overflow, and pass through:"], ["e lofia ai e ia le nuu ma ui ane ai;", "then shall he return,"], ["ona toe laga mai lea o ia e oo i lona 'olo.", "and be stirred up, even to his fortress."]]},
  {num:11,words:[["E matuā ita foi le tupu o le itu i toga,", "And the king of the south shall be moved with choler,"], ["ona alu atu lea o ia la te tau ma le tupu o le itu i matu;", "and shall come forth and fight with him,"], ["na te aveina atu 'au e tele lava;", "even with the king of the north: and he shall set forth a great multitude;"], ["a e tuuina atu i lana pule le vao 'au e tele.", "but the multitude shall be given into his hand."]]},
  {num:12,words:[["A aveesea foi ia 'au e tele ona faamaualugaina ai lea o lona loto;", "And when he hath taken away the multitude,"], ["e manomano foi o e lafotuina e ia,", "his heart shall be lifted up; and he shall cast down many ten thousands:"], ["a e le malosi ai o ia.", "but he shall not be strengthened by it."]]},
  {num:13,words:[["Auā e toe foi mai le tupu o le itu i matu,", "For the king of the north shall return,"], ["na te aveina atu 'au e sili ona tele i e na muamua; a mavae isi tausaga e sau ai lava o ia ma 'au e tele,", "and shall set forth a multitude greater than the former,"], ["atoa ma le oloa tele.", "and shall certainly come after certain years with a great army and with much riches."]]},
  {num:14,words:[["O ia ona po foi e toatele latou te tutū atu e tetee atu i le tupu o le itu i toga;", "And in those times there shall many stand up against the king of the south:"], ["e faamaualuga foi tagata e i lou nuu, latou te faataunuu ai le faaaliga,", "also the robbers of thy people shall exalt themselves to establish the vision;"], ["a e pauu i latou.", "but they shall fall."]]},
  {num:15,words:[["Ona sau ai lea o le tupu o le itu i matu,", "So the king of the north shall come,"], ["e tanu e ia se mea maupuepue,", "and cast up a mount,"], ["na te aea aai nofo'olo;", "and take the most fenced cities:"], ["o 'au foi a le itu i toga,", "and the arms of the south shall not withstand,"], ["atoa ma ona tagata ua filifilia latou te le tetee atu,", "neither his chosen people,"], ["e leai lava se malosi e tetee atu ai.", "neither shall there be any strength to withstand."]]},
  {num:16,words:[["O lē atu ia te ia na te faia mea ua ia loto i ai,", "But he that cometh against him shall do according to his own will,"], ["e leai foi se tasi e tu i ona luma;", "and none shall stand before him:"], ["e tu lava ia i le nuu matagofie,", "and he shall stand in the glorious land,"], ["e faaumaina foi i lona lima.", "which by his hand shall be consumed."]]},
  {num:17,words:[["E faasaga foi o ia ina ia alu atu ma le 'au tau o lona malo uma,", "He shall also set his face to enter with the strength of his whole kingdom,"], ["e faatasi foi ma ia e amiotonu,", "and upright ones with him;"], ["ma na faia lava;", "thus shall he do: and he shall give him the daughter of women,"], ["na te avatu foi ia te ia le teine muli ina ia leaga ai le loto o le teine;", "corrupting her:"], ["a e le tumau ai o ia,", "but she shall not stand on his side,"], ["e le 'au faatasi foi ma ia.", "neither be for him."]]},
  {num:18,words:[["Ona faasaga lea o ia i nuu tu tai,", "After this shall he turn his face unto the isles,"], ["ma na faoa nuu e tele;", "and shall take many:"], ["a o le tasi alii na te faaiuina e ia lona gao; na te faaliliu atu foi ia te ia lea mea,", "but a prince for his own behalf shall cause the reproach offered by him to cease;"], ["a e le gaogaoina ai o ia.", "without his own reproach he shall cause it to turn upon him."]]},
  {num:19,words:[["Ona toe faasaga lea o ia i le 'olo o lona nuu;", "Then he shall turn his face toward the fort of his own land:"], ["a e tausuai o ia ma paū,", "but he shall stumble and fall,"], ["e le toe iloa foi o ia.", "and not be found."]]},
  {num:20,words:[["A e tu mai se tasi i lana nofoaiga,", "Then shall stand up in his estate a raiser of taxes in the glory of the kingdom:"], ["o le na te faaui ane le faau taulaga i le nuu matagofie o lona malo;", "but within few days he shall be destroyed,"], ["a e mavae nai aso ona fano ai lea o ia,", "neither in anger,"], ["a e le o se ita po o se taua.", "nor in battle."]]},
  {num:21,words:[["Ona tu mai lea i lana nofoaiga o le e inosia,", "And in his estate shall stand up a vile person,"], ["latou te le tuuina atu ia te ia le mamalu o le malo;", "to whom they shall not give the honour of the kingdom:"], ["a e sau faafifilemu ia,", "but he shall come in peaceably,"], ["o faaoleolega foi na te maua mai ai le malo.", "and obtain the kingdom by flatteries."]]},
  {num:22,words:[["O 'au foi a e lolofi mai e lofia ai i latou mai ona luma,", "And with the arms of a flood shall they be overflown from before him,"], ["e faaumatia ai i latou,", "and shall be broken; yea,"], ["atoa ma le alii o le feagaiga.", "also the prince of the covenant."]]},
  {num:23,words:[["A uma foi ona sosoo ma ia,", "And after the league made with him he shall work deceitfully:"], ["e fai mea pepelo lava ia; auā e alu ae lava ia,", "for he shall come up,"], ["o se nuu itiiti foi e malosi ai o ia.", "and shall become strong with a small people."]]},
  {num:24,words:[["E alu atu o ia ma le fifilemu i mea e sili ona lelei o le itu malo;", "He shall enter peaceably even upon the fattest places of the province;"], ["na te faia foi mea na le faia e ona tamā,", "and he shall do that which his fathers have not done,"], ["po o tamā o ona tamā;", "nor his fathers' fathers;"], ["na te tufatufaina ia te i latou o mea faoa,", "he shall scatter among them the prey,"], ["ma vete,", "and spoil, and riches:"], ["atoa ma oloa,", "yea,"], ["na te taumafaufau i lona loto e aea ai 'olo,", "and he shall forecast his devices against the strong holds,"], ["seia oo i se aso.", "even for a time."]]},
  {num:25,words:[["E faamalosi atu foi o ia ma lona loto atoa e tau ma le tupu o le itu i toga, ma le itu taua e toatele;", "And he shall stir up his power and his courage against the king of the south with a great army;"], ["o le tupu foi o le itu i toga e laga mai o ia i le taua,", "and the king of the south shall be stirred up to battle with a very great and mighty army;"], ["ma le itu taua tele ma le malosi tele lava;", "but he shall not stand:"], ["a e le tumau o ia, auā latou te taupulepule ia te ia.", "for they shall forecast devices against him."]]},
  {num:26,words:[["O e aai i ana mea taumafa,", "Yea,"], ["e fano ai o ia,", "they that feed of the portion of his meat shall destroy him,"], ["e lolofi mai foi ana 'au;", "and his army shall overflow:"], ["e toatele foi e fasiotia.", "and many shall fall down slain."]]},
  {num:27,words:[["E finagalo ia tupu e lua e fai mea leaga,", "And both these kings' hearts shall be to do mischief,"], ["la te tala pepelo i le laoai e tasi;", "and they shall speak lies at one table;"], ["a e le manuia ai,", "but it shall not prosper:"], ["auā e oo lava le iuga i ona po ua atofaina ai.", "for yet the end shall be at the time appointed."]]},
  {num:28,words:[["Ona toe foi ai lea o ia i lona nuu ma le oloa tele;", "Then shall he return into his land with great riches;"], ["e ita foi o ia i le feagaiga paia;", "and his heart shall be against the holy covenant;"], ["na te faia foi lona loto ,", "and he shall do exploits,"], ["ona toe foi lea o ia i lona nuu.", "and return to his own land."]]},
  {num:29,words:[["O ona po ua tuupoina e toe foi mai ai o ia,", "At the time appointed he shall return,"], ["ma alu atu i le itu i toga;", "and come toward the south;"], ["a e le iu faapei o le na muamua,", "but it shall not be as the former,"], ["po o lē mulimuli.", "or as the latter."]]},
  {num:30,words:[["Auā e alu atu le fua Kitimo e tetee atu ia te ia;", "For the ships of Chittim shall come against him:"], ["e tigaina ai lona loto,", "therefore he shall be grieved,"], ["ona toe foi mai ai lea,", "and return, and have indignation against the holy covenant:"], ["o ita atu foi o ia i le feagaiga paia;", "so shall he do;"], ["na te faapea lava ona fai,", "he shall even return,"], ["na te toe foi mai ma faasaga lona manatu i e ua lafoai le feagaiga paia.", "and have intelligence with them that forsake the holy covenant."]]},
  {num:31,words:[["O 'au foi latou te 'au ma ia,", "And arms shall stand on his part,"], ["latou te faaleagaina le malumalu e malu ai,", "and they shall pollute the sanctuary of strength,"], ["latou te aveeseina foi le taulaga fai soo,", "and shall take away the daily sacrifice,"], ["ma tuuina ai le mea inosia e faatafunaina ai.", "and they shall place the abomination that maketh desolate."]]},
  {num:32,words:[["O e agasala i le feagaiga e leaga i latou ia te ia i faaoleolega;", "And such as do wickedly against the covenant shall he corrupt by flatteries: but the people that do know their God shall be strong,"], ["a o le nuu o e ua iloa lo latou Atua latou te faamalolosi ma fai mea tetele .", "and do exploits."]]},
  {num:33,words:[["O e ua popoto i le nuu latou te a'oa'oina atu i tagata e toatele;", "And they that understand among the people shall instruct many: yet they shall fall by the sword,"], ["a o aso e tele e pauu ai i latou i le pelu ma le afi,", "and by flame,"], ["ma le tafeaga,", "by captivity,"], ["ma le veteina.", "and by spoil, many days."]]},
  {num:34,words:[["A pauu foi i latou,", "Now when they shall fall,"], ["latou te maua se fesoasoani, o se fesoasoani itiiti;", "they shall be holpen with a little help:"], ["a e toetele e pipii atu ia te i latou ma faaoleolega.", "but many shall cleave to them with flatteries."]]},
  {num:35,words:[["E pauu foi nisi o e popoto,", "And some of them of understanding shall fall,"], ["e tofotofoina ai i latou,", "to try them,"], ["ma faamamāina ai,", "and to purge,"], ["ma faasinasinaina ai,", "and to make them white,"], ["seia oo i ona po o le iuga;", "even to the time of the end:"], ["auā e lei oo i ona po ua tuupoina.", "because it is yet for a time appointed."]]},
  {num:36,words:[["O le tupu foi na te faia e tusa ma lona loto,", "And the king shall do according to his will;"], ["ma faamaualuga o ia e ia,", "and he shall exalt himself,"], ["ma faasili ia te ia i atua uma;", "and magnify himself above every god,"], ["na te faia upu faasausili i le Atua o atua,", "and shall speak marvellous things against the God of gods,"], ["e manuia foi o ia seia atoatoa le toasa;", "and shall prosper till the indignation be accomplished:"], ["auā e faia lava le mea ua tuu i ai le pule.", "for that that is determined shall be done."]]},
  {num:37,words:[["Na te le manatu i le Atua o ona tamā,", "Neither shall he regard the God of his fathers,"], ["na te le manatu i le manao i fafine,", "nor the desire of women,"], ["na te le manatu foi i se tasi atua;", "nor regard any god:"], ["auā e faasilisili o ia e ia i mea uma.", "for he shall magnify himself above all."]]},
  {num:38,words:[["E ava o ia i le atua o 'olo i le mea e nofo ai o ia;", "But in his estate shall he honour the God of forces:"], ["o le atua foi sa le iloa e ona tamā na te ava i ai,", "and a god whom his fathers knew not shall he honour with gold,"], ["ma avatu i ai auro, ma ario,", "and silver,"], ["ma maa tāua,", "and with precious stones,"], ["atoa ma mea matagofie.", "and pleasant things."]]},
  {num:39,words:[["E faia lava lea e ia i 'olo e sili ona malolosi,", "Thus shall he do in the most strong holds with a strange god,"], ["i le atua ese,", "whom he shall acknowledge and increase with glory:"], ["o le e manatua e ia ma faasilisili ona ava i ai; na te tuuina atu foi ia te i latou le pule i tagata e toatele,", "and he shall cause them to rule over many,"], ["na te vaevaeina foi le laueleele e maua ai le taui.", "and shall divide the land for gain."]]},
  {num:40,words:[["A oo i ona po o le iuga,", "And at the time of the end shall the king of the south push at him:"], ["ona sii atu lea ia te ia o le taua e le tupu o le itu i toga;", "and the king of the north shall come against him like a whirlwind,"], ["e pei se afā ona oso atu ia te ia o le tupu o le itu i matu ma kariota,", "with chariots,"], ["ma e o tietie i solofanua, atoa ma vaa e tele;", "and with horsemen,"], ["na te oo atu foi i nuu,", "and with many ships;"], ["ma lolofi i ai,", "and he shall enter into the countries,"], ["ma ui ane ai.", "and shall overflow and pass over."]]},
  {num:41,words:[["E oo atu foi o ia i le nuu matagofie,", "He shall enter also into the glorious land,"], ["e faaumatia foi nuu e tele;", "and many countries shall be overthrown:"], ["a e sao nai lona lima o nuu ia,", "but these shall escape out of his hand,"], ["o Etoma,", "even Edom,"], ["ma Moapi,", "and Moab,"], ["atoa ma e ua sili i le fanauga a Amoni.", "and the chief of the children of Ammon."]]},
  {num:42,words:[["Na te faaoo atu lona lima i nuu,", "He shall stretch forth his hand also upon the countries:"], ["e le sao foi le nuu o Aikupito.", "and the land of Egypt shall not escape."]]},
  {num:43,words:[["A e pule o ia oloa,", "But he shall have power over the treasures of gold and of silver,"], ["o auro, ma ario atoa ma mea matagofie uma o Aikupito;", "and over all the precious things of Egypt:"], ["e mulimuli atu foi ia te ia o Lipua ma Aitiope.", "and the Libyans and the Ethiopians shall be at his steps."]]},
  {num:44,words:[["A o tala mai sasae,", "But tidings out of the east and out of the north shall trouble him:"], ["ma le itu i matu e atuatuvale ai o ia;", "therefore he shall go forth with great fury to destroy,"], ["ona alu atu ai lea o ia ma le ita tele ia faaumatia ma fasiotia tagata e toatele.", "and utterly to make away many."]]},
  {num:45,words:[["Na te faatuina fale ie o lona maota i le va o sami,", "And he shall plant the tabernacles of his palace between the seas in the glorious holy mountain;"], ["i le mauga matagofie ma le paia; a e oo atu i lona iuga,", "yet he shall come to his end,"], ["e leai foi se tasi e fesoasoani ia te ia.", "and none shall help him."]]},
];
renderVerseSet(dan_ch_11_Verses, 'dan-ch11-verses');

var dan_ch_12_Verses = [
  {num:1,words:[["O ona po foi ia e tulai ai Mekaeli,", "And at that time shall Michael stand up,"], ["o le alii sili, o le na te tulai ona o tagata o lou nuu;", "the great prince which standeth for the children of thy people:"], ["e oo mai foi aso vale,", "and there shall be a time of trouble,"], ["e leai sona tusa talu ona faatoa tupu o nuu,", "such as never was since there was a nation even to that same time:"], ["ua oo i ia lava aso; o ona po foi ia e laveaiina ai ou tagata,", "and at that time thy people shall be delivered,"], ["o i latou uma o e ua tusia i le tusi.", "every one that shall be found written in the book."]]},
  {num:2,words:[["E toatele foi o e momoe i le efuefu o le eleele latou te ala mai,", "And many of them that sleep in the dust of the earth shall awake,"], ["o isi i le ola e faavavau,", "some to everlasting life,"], ["a o isi i le faalumaina ma le inosia e faavavau.", "and some to shame and everlasting contempt."]]},
  {num:3,words:[["O e popoto foi, e fepulafi i latou faapei o le pupula o le lagi;", "And they that be wise shall shine as the brightness of the firmament;"], ["o i latou foi ua faaliliu ai tagata e toatele ia amiotonu, e pei o fetu i latou e faavavau faavavau lava.", "and they that turn many to righteousness as the stars for ever and ever."]]},
  {num:4,words:[["A o oe Tanielu e,", "But thou,"], ["ia e pupuni o ia upu,", "O Daniel,"], ["ma faamaufaailogaina le tusi,", "shut up the words, and seal the book,"], ["seia oo i ona po o le iuga;", "even to the time of the end:"], ["e fetaufetuliai tagata e toatele,", "many shall run to and fro,"], ["e tupu tele foi le malamalama.", "and knowledge shall be increased."]]},
  {num:5,words:[["O a'u Tanielu,", "Then I Daniel looked,"], ["na a'u vaai atu,", "and,"], ["faauta foi,", "behold,"], ["o isi e toalua ua tutū mai,", "there stood other two,"], ["o le tasi i le auvai i le itu vai mai o le vaitafe,", "the one on this side of the bank of the river,"], ["a o le tasi i le auvai i lela itu o le vaitafe.", "and the other on that side of the bank of the river."]]},
  {num:6,words:[["Ona faapea atu lea o le tasi i le tagata ua ofu i le ie lino,", "And one said to the man clothed in linen,"], ["ua i luga o le vai o le vaitafe,", "which was upon the waters of the river,"], ["Pe oo mai afea le iuga o ia mea e ofo ai?", "How long shall it be to the end of these wonders?"]]},
  {num:7,words:[["Ona a'u faalogo lea i le tagata ua ofu i le ie lino,", "And I heard the man clothed in linen,"], ["ua i luga o le vai o le vaitafe,", "which was upon the waters of the river,"], ["ua sii i luga i le lagi lona lima taumatau ma lona lima tauagavale,", "when he held up his right hand and his left hand unto heaven,"], ["ua tauto foi o ia i le soifua e faavavau,", "and sware by him that liveth for ever that it shall be for a time,"], ["e oo ia mea i le tausaga, ma tausaga,", "times,"], ["ma le vaeluagalemu o le tausaga;", "and an half;"], ["a uma foi ona faataapeapeina le malosi o le nuu paia,", "and when he shall have accomplished to scatter the power of the holy people,"], ["ona taunuu foi lea o na mea uma.", "all these things shall be finished."]]},
  {num:8,words:[["Na a'u faalogo foi,", "And I heard,"], ["a ua ou le lagona;", "but I understood not:"], ["ona ou faapea atu lea,", "then said I,"], ["Le alii e,", "O my Lord,"], ["pe se a le iuga o ia mea?", "what shall be the end of these things?"]]},
  {num:9,words:[["Ona faapea mai lea o ia,", "And he said,"], ["Tanielu e,", "Go thy way,"], ["ina alu ia;", "Daniel:"], ["auā ua punitia ma faamaufaailogaina o upu seia oo i ona po o le iuga.", "for the words are closed up and sealed till the time of the end."]]},
  {num:10,words:[["E toatele e faamamāina,", "Many shall be purified,"], ["ma faasinasinaina,", "and made white,"], ["ma tofotofoina;", "and tried;"], ["a e agasala o e agasala,", "but the wicked shall do wickedly:"], ["e le lagona foi so latou toatasi o e agasala;", "and none of the wicked shall understand;"], ["a o e popoto e lagona lava i latou.", "but the wise shall understand."]]},
  {num:11,words:[["E afua i ona po e aveeseina ai le taulaga e fai i aso fai soo,", "And from the time that the daily sacrifice shall be taken away,"], ["e oo foi i le tuuina atu o le mea inosia e faatafunaina ai, e atoa aso e tasi le afe,", "and the abomination that maketh desolate set up,"], ["ma le lua o selau ma le ivagafulu.", "there shall be a thousand two hundred and ninety days."]]},
  {num:12,words:[["Amuia o lē faatalitali atu ma aulia atu ona aso e afe ma le tolu o selau,", "Blessed is he that waiteth,"], ["ma le tolugafulu ma le lima.", "and cometh to the thousand three hundred and five and thirty days."]]},
  {num:13,words:[["A o oe ia e alu atu seia oo i le iuga;", "But go thou thy way till the end be:"], ["auā e te malolo,", "for thou shalt rest,"], ["e te tu mai foi i lou tofi pe a oo i le iuga o aso.", "and stand in thy lot at the end of the days."]]},
];
renderVerseSet(dan_ch_12_Verses, 'dan-ch12-verses');

})();